def timeline_first_keyframe_apply_preview_packet(
    keyframes: list[object] | None = None,
    applied: bool = False,
    reason: str = "ack_endpoint_preview_only",
    active_step_state: dict[str, object] | None = None,
) -> dict[str, object]:
    keyframes = [keyframe for keyframe in keyframes if isinstance(keyframe, dict)] if isinstance(keyframes, list) else []
    active_step_state = active_step_state if isinstance(active_step_state, dict) else None
    selected_index = 0
    if active_step_state is not None:
        active_index = active_step_state.get("active_index")
        if isinstance(active_index, int) and 0 <= active_index < len(keyframes):
            selected_index = active_index
    first = keyframes[selected_index] if keyframes else None
    snapshot = first.get("layer_stack_snapshot") if isinstance(first, dict) else None
    layers = snapshot.get("layers") if isinstance(snapshot, dict) else None
    material = first.get("ocean_material") if isinstance(first, dict) else None
    camera = timeline_camera_payload(first) if isinstance(first, dict) else None
    return {
        "schema": "rrkal_displaytools.timeline_first_keyframe_apply.v1",
        "mode": "renderer_startup_active_step_keyframe" if active_step_state is not None else "renderer_startup_first_keyframe",
        "applied": bool(applied),
        "available": first is not None,
        "reason": reason,
        "active_step_state": active_step_state,
        "active_index": selected_index if first is not None else None,
        "keyframe_id": str(first.get("id", "")) if isinstance(first, dict) else None,
        "detected_scope": {
            "style_profile": bool(first.get("style_profile")) if isinstance(first, dict) else False,
            "ocean_material": isinstance(material, dict),
            "layer_stack_snapshot": isinstance(layers, dict),
            "pins": isinstance(first.get("pins"), list) if isinstance(first, dict) else False,
            "boundary_highlight": isinstance(first.get("boundary_highlight"), dict) if isinstance(first, dict) else False,
            "boundary_emphasis_control": isinstance(first.get("boundary_emphasis_control"), dict) if isinstance(first, dict) else False,
            "camera": camera is not None,
        },
        "changed": {
            "style_profile": False,
            "ocean_material": [],
            "layer_visibility": [],
            "layer_opacity": [],
            "layer_blend": [],
            "selected_layer": False,
            "pins": False,
            "selected_pin_id": False,
            "boundary_highlight": False,
            "boundary_emphasis_control": False,
            "camera": False,
        },
        "unsupported_scope": [],
        "boundary": "Preview/apply packet for startup first-keyframe handling; this is not renderer animation playback.",
    }


def write_timeline_ack_payload(timeline_ack_file: str | Path | None, payload: dict[str, object]) -> None:
    if not timeline_ack_file:
        return
    path = Path(timeline_ack_file)
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def _pin_label_text(pin: dict[str, object]) -> str:
    text = str(pin.get("label") or pin.get("id") or "Pin").strip()
    if len(text) > 28:
        return text[:25] + "..."
    return text or "Pin"


def _pin_label_priority(pin: dict[str, object]) -> int:
    value = pin.get("label_priority", 50)
    if isinstance(value, bool):
        return 50
    try:
        return max(0, min(100, int(value)))
    except (TypeError, ValueError):
        return 50


def _boxes_intersect(a: tuple[int, int, int, int], b: tuple[int, int, int, int], pad: int = 4) -> bool:
    return not (
        a[2] + pad <= b[0]
        or b[2] + pad <= a[0]
        or a[3] + pad <= b[1]
        or b[3] + pad <= a[1]
    )


def _clamp_label_box(box: tuple[int, int, int, int], width: int, height: int) -> tuple[int, int, int, int]:
    x0, y0, x1, y1 = box
    box_w = x1 - x0
    box_h = y1 - y0
    x0 = max(0, min(width - box_w - 1, x0))
    y0 = max(0, min(height - box_h - 1, y0))
    return x0, y0, x0 + box_w, y0 + box_h


def _pin_label_candidates(
    x: int,
    y: int,
    text: str,
    marker_radius: int,
    width: int,
    height: int,
) -> list[tuple[int, int, int, int]]:
    label_w = max(42, min(220, len(text) * 7 + 14))
    label_h = 18
    gap = marker_radius + 8
    raw = [
        (x + gap, y - label_h - 4, x + gap + label_w, y - 4),
        (x + gap, y + 4, x + gap + label_w, y + 4 + label_h),
        (x - gap - label_w, y - label_h - 4, x - gap, y - 4),
        (x - gap - label_w, y + 4, x - gap, y + 4 + label_h),
    ]
    return [_clamp_label_box(box, width, height) for box in raw]


def _draw_pin_label_fallback(
    overlay: np.ndarray,
    planned: list[dict[str, object]],
    marker_style: dict[str, object],
) -> None:
    label_bg = marker_style["label_bg"]
    label_line = marker_style["label_line"]
    for item in planned:
        x = int(item["x"])
        y = int(item["y"])
        x0, y0, x1, y1 = item["box"]
        cx = max(x0, min(x1 - 1, x))
        cy = max(y0, min(y1 - 1, y))
        steps = max(abs(cx - x), abs(cy - y), 1)
        for step in range(steps + 1):
            px = int(round(x + (cx - x) * step / steps))
            py = int(round(y + (cy - y) * step / steps))
            if 0 <= py < overlay.shape[0] and 0 <= px < overlay.shape[1]:
                overlay[py, px, :3] = label_line[:3]
                overlay[py, px, 3] = max(int(overlay[py, px, 3]), int(label_line[3]))
        region = overlay[y0:y1, x0:x1]
        region[..., :3] = label_bg[:3]
        region[..., 3] = np.maximum(region[..., 3], int(label_bg[3]))


def _draw_pin_labels(
    overlay: np.ndarray,
    labels: list[dict[str, object]],
    marker_style: dict[str, object],
    width: int,
    height: int,
    label_mode: str = "auto",
    label_min_priority: int = 50,
) -> None:
    occupied: list[tuple[int, int, int, int]] = []
    planned: list[dict[str, object]] = []
    mode = str(label_mode or "auto")
    if mode not in {"auto", "selected", "priority", "hidden"}:
        mode = "auto"
    try:
        min_priority = max(0, min(100, int(label_min_priority)))
    except (TypeError, ValueError):
        min_priority = 50
    filtered: list[dict[str, object]] = []
    for label in labels:
        selected = bool(label.get("selected", False))
        priority = int(label.get("priority", 50))
        if mode == "hidden":
            continue
        if selected:
            filtered.append(label)
        elif mode == "selected":
            continue
        elif mode == "priority" and priority < min_priority:
            continue
        else:
            filtered.append(label)
    ordered_labels = sorted(
        filtered,
        key=lambda item: (
            not bool(item.get("selected", False)),
            -int(item.get("priority", 50)),
            str(item.get("text", "")),
        ),
    )
    for label in ordered_labels[:24]:
        x = int(label["x"])
        y = int(label["y"])
        text = str(label["text"])
        marker_radius = int(label["marker_radius"])
        for box in _pin_label_candidates(x, y, text, marker_radius, width, height):
            if any(_boxes_intersect(box, other) for other in occupied):
                continue
            occupied.append(box)
            planned.append({"x": x, "y": y, "text": text, "box": box})
            break
    if not planned:
        return
    try:
        from PIL import Image, ImageDraw, ImageFont

        image = Image.fromarray(overlay, mode="RGBA")
        draw = ImageDraw.Draw(image, mode="RGBA")
        font = ImageFont.load_default()
        label_bg = tuple(marker_style["label_bg"])
        label_text = tuple(marker_style["label_text"])
        label_line = tuple(marker_style["label_line"])
        for item in planned:
            x = int(item["x"])
            y = int(item["y"])
            x0, y0, x1, y1 = item["box"]
            draw.line((x, y, (x0 + x1) // 2, (y0 + y1) // 2), fill=label_line, width=1)
            draw.rectangle((x0, y0, x1, y1), fill=label_bg, outline=label_line)
            draw.text((x0 + 5, y0 + 3), str(item["text"]), fill=label_text, font=font)
        overlay[:] = np.asarray(image, dtype=np.uint8)
    except Exception:
        _draw_pin_label_fallback(overlay, planned, marker_style)


def render_pin_overlay(
    width: int,
    height: int,
    projected_pins: list[dict[str, object]],
    pin_size: int = 9,
    selected_pin_id: str | None = None,
    style_profile: str = "scientific",
    label_mode: str = "auto",
    label_min_priority: int = 50,
) -> np.ndarray:
    overlay = np.zeros((height, width, 4), dtype=np.uint8)
    radius = max(2, int(pin_size) // 2)
    marker_style = resolve_pin_marker_style(style_profile)
    marker_colors = marker_style["colors"]
    selected_ring = marker_style["selected_ring"]
    center_color = marker_style["center"]
    labels: list[dict[str, object]] = []
    for pin in projected_pins:
        if not bool(pin.get("visible", False)):
            continue
        try:
            x = int(round(float(pin["screen_x"])))
            y = int(round(float(pin["screen_y"])))
        except (KeyError, TypeError, ValueError):
            continue
        selected = selected_pin_id is not None and pin.get("id") == selected_pin_id
        color = marker_colors.get(str(pin.get("type", "Observation")), marker_colors["Observation"])
        marker_radius = radius + (2 if selected else 0)
        ring_radius = marker_radius + (3 if selected else 0)
        for dy in range(-ring_radius, ring_radius + 1):
            py = y + dy
            if py < 0 or py >= height:
                continue
            for dx in range(-ring_radius, ring_radius + 1):
                px = x + dx
                if px < 0 or px >= width:
                    continue
                dist2 = dx * dx + dy * dy
                if selected and marker_radius * marker_radius < dist2 <= ring_radius * ring_radius:
                    overlay[py, px, :3] = selected_ring[:3]
                    overlay[py, px, 3] = max(int(overlay[py, px, 3]), int(selected_ring[3]))
                elif dist2 <= marker_radius * marker_radius or dx == 0 or dy == 0:
                    alpha = color[3] if dist2 <= marker_radius * marker_radius else 190
                    overlay[py, px, :3] = color[:3]
                    overlay[py, px, 3] = max(int(overlay[py, px, 3]), alpha)
        if 0 <= x < width and 0 <= y < height:
            overlay[y, x, :3] = center_color[:3]
            overlay[y, x, 3] = center_color[3]
        labels.append(
            {
                "x": x,
                "y": y,
                "text": _pin_label_text(pin),
                "marker_radius": marker_radius,
                "priority": _pin_label_priority(pin),
                "selected": selected,
            }
        )
    _draw_pin_labels(overlay, labels, marker_style, width, height, label_mode, label_min_priority)
    return overlay


def alpha_compose_transparent(background: np.ndarray, overlay: np.ndarray) -> np.ndarray:
    if overlay.shape != background.shape:
        raise ValueError(f"Overlay shape {overlay.shape} does not match background {background.shape}")
    bg = background.astype(np.float32) / 255.0
    fg = overlay.astype(np.float32) / 255.0
    fg_a = fg[..., 3:4]
    bg_a = bg[..., 3:4]
    out_a = fg_a + bg_a * (1.0 - fg_a)
    safe_a = np.maximum(out_a, 1e-6)
    out_rgb = (fg[..., :3] * fg_a + bg[..., :3] * bg_a * (1.0 - fg_a)) / safe_a
    out = np.zeros_like(background)
    out[..., :3] = np.clip(out_rgb * 255.0, 0.0, 255.0).astype(np.uint8)
    out[..., 3:4] = np.clip(out_a * 255.0, 0.0, 255.0).astype(np.uint8)
    return out


def scale_bar_geometry(width: int, height: int, zoom: float, x: float, y: float) -> tuple[float, float, float, float]:
    km_per_px = max(0.001, 6371.0 * float(zoom) * 2.0 / max(1.0, float(min(width, height))))
    target_px = max(80.0, min(220.0, float(width) * 0.18))
    raw_km = max(1.0, target_px * km_per_px)
    magnitude = 10.0 ** math.floor(math.log10(raw_km))
    normalized = raw_km / magnitude
    if normalized >= 5.0:
        nice = 5.0 * magnitude
    elif normalized >= 2.0:
        nice = 2.0 * magnitude
    else:
        nice = magnitude
    px = max(40.0, nice / km_per_px)
    x0 = max(8.0, min(float(x), max(8.0, float(width) - px - 12.0)))
    y0 = max(24.0, min(float(y), max(24.0, float(height) - 16.0)))
    return x0, y0, x0 + px, nice


class FPSRecorder:
    def __init__(self, path: str | Path | None = None):
        self.path = Path(path or (CACHE_DIR / "fps_log.jsonl"))
        self.samples: list[dict] = []
        self.last_tick = time.time()
        atexit.register(self.close)

    def tick(self) -> None:
        now = time.time()
        delta = max(1e-6, now - self.last_tick)
        self.last_tick = now
        self.samples.append({"time": now, "fps": 1.0 / delta})
        if len(self.samples) > 6000:
            self.samples = self.samples[-3000:]

    def close(self) -> None:
        if not self.samples:
            return
        try:
            self.path.parent.mkdir(parents=True, exist_ok=True)
            with self.path.open("a", encoding="utf-8") as fh:
                for sample in self.samples:
                    fh.write(json.dumps(sample, ensure_ascii=False) + "\n")
            self.samples.clear()
        except Exception:
            return


FOREST_EVENT_CMAP = ["#fff3b0", "#ffb703", "#fb8500", "#e85d04", "#d00000"]


def normalize_forest_event_frame(frame: pd.DataFrame) -> pd.DataFrame:
    if frame.empty:
        return pd.DataFrame(columns=["lon", "lat", "frp", "confidence", "timestamp", "event_type"])
    lat_col = find_column(frame, LAT_ALIASES)
    lon_col = find_column(frame, LON_ALIASES)
    if lat_col is None or lon_col is None:
        raise ValueError("Forest event data must contain latitude/longitude columns.")
    out = pd.DataFrame(
        {
            "lat": pd.to_numeric(frame[lat_col], errors="coerce"),
            "lon": pd.to_numeric(frame[lon_col], errors="coerce"),
        }
    )
    frp_col = find_column(frame, ("frp", "power", "radiative_power", "brightness", "bright_ti4", "bright_ti5"))
    confidence_col = find_column(frame, ("confidence", "conf", "confidence_pct", "confidence_percent"))
    time_col = find_column(frame, ("timestamp", "time", "acq_datetime", "acq_time", "date", "acq_date"))
    type_col = find_column(frame, ("event_type", "type", "class", "source"))
    out["frp"] = pd.to_numeric(frame[frp_col], errors="coerce") if frp_col is not None else 1.0
    out["confidence"] = pd.to_numeric(frame[confidence_col], errors="coerce") if confidence_col is not None else 75.0
    if time_col is not None:
        out["timestamp"] = pd.to_datetime(frame[time_col], errors="coerce", utc=True)
    else:
        out["timestamp"] = pd.Timestamp.now(tz="UTC")
    out["event_type"] = frame[type_col].astype(str) if type_col is not None else "fire"
    out = out.dropna(subset=["lat", "lon"])
    out = out[(out["lat"].between(-90, 90)) & (out["lon"].between(-180, 180))]
    return out.reset_index(drop=True)


def dataframe_from_forest_event_text(text: str, source_name: str) -> pd.DataFrame:
    return normalize_forest_event_frame(dataframe_from_text(text, source_name))


def simulated_forest_events(count: int = 1600) -> pd.DataFrame:
    rng = np.random.default_rng(38291)
    centers = np.array(
        [
            [-4.5, -62.0],
            [-2.0, 112.0],
            [-18.0, 132.0],
            [55.0, -112.0],
            [61.0, 98.0],
            [-12.0, 24.0],
        ],
        dtype=np.float32,
    )
    choice = rng.integers(0, len(centers), size=count)
    lat = centers[choice, 0] + rng.normal(0.0, 3.2, size=count)
    lon = centers[choice, 1] + rng.normal(0.0, 5.8, size=count)
    frp = np.clip(rng.lognormal(mean=2.1, sigma=0.9, size=count), 0.5, 650.0)
    confidence = np.clip(rng.normal(78.0, 15.0, size=count), 15.0, 100.0)
    return pd.DataFrame(
        {
            "lat": lat.astype(np.float32),
            "lon": lon.astype(np.float32),
            "frp": frp.astype(np.float32),
            "confidence": confidence.astype(np.float32),
            "timestamp": pd.Timestamp.now(tz="UTC"),
            "event_type": "fire",
        }
    )


class ForestEventSource:
    def __init__(self, event_url: str | None, event_file: str | None, timeout: float, demo: bool):
        self.event_url = event_url
        self.event_file = event_file
        self.timeout = timeout
        self.demo = bool(demo)

    def read(self) -> pd.DataFrame:
        if self.event_file:
            path = Path(self.event_file)
            text = path.read_text(encoding="utf-8")
            return dataframe_from_forest_event_text(text, str(path))
        if self.event_url:
            text = read_url_text(self.event_url, self.timeout)
            return dataframe_from_forest_event_text(text, self.event_url)
        if self.demo:
            return simulated_forest_events()
        return pd.DataFrame(columns=["lon", "lat", "frp", "confidence", "timestamp", "event_type"])


class ForestEventDatashaderOverlay:
    def __init__(self, width: int, height: int, point_px: int, frp_span: tuple[float, float]):
        self.width = width
        self.height = height
        self.point_px = point_px
        self.frp_span = frp_span
        self.canvas = ds.Canvas(
            plot_width=width,
            plot_height=height,
            x_range=(0.0, float(width)),
            y_range=(0.0, float(height)),
        )
        self.empty = np.zeros((height, width, 4), dtype=np.uint8)

    def render(self, projected: pd.DataFrame) -> np.ndarray:
        if projected.empty:
            return self.empty.copy()
        if "frp" in projected.columns and projected["frp"].notna().any():
            agg = self.canvas.points(projected, "screen_x", "screen_y", agg=ds.max("frp"))
            overlay = tf.shade(
                agg,
                cmap=FOREST_EVENT_CMAP,
                how="linear",
                span=self.frp_span,
                min_alpha=90,
                name="forest_events_frp",
            )
        else:
            agg = self.canvas.points(projected, "screen_x", "screen_y", agg=ds.count())
            overlay = tf.shade(
                agg,
                cmap=FOREST_EVENT_CMAP,
                how="eq_hist",
                min_alpha=90,
                name="forest_events_density",
            )
        if self.point_px > 1:
            overlay = tf.dynspread(overlay, threshold=0.45, max_px=self.point_px)
        return np.asarray(overlay.to_pil().convert("RGBA"), dtype=np.uint8)


def load_vector_geojson_from_source(
    name: str,
    file_path: str | None = None,
    url: str | None = None,
    natural_earth_layer: str | None = None,
    natural_earth_source: str = "naturalearth",
) -> dict | None:
    try:
        if file_path:
            path = Path(file_path)
            if not path.exists():
                record_data_fetch_event("file", name, "missing", source=str(path), message="vector file not found")
                print(f"{name} vector file not found: {path}")
                return None
            record_data_fetch_event("file", name, "read", source=str(path), message="reading local vector source")
            suffix = path.suffix.lower()
            if suffix in {".json", ".geojson"}:
                return json.loads(path.read_text(encoding="utf-8"))
            if suffix in {".gpkg", ".shp", ".zip"}:
                try:
                    import geopandas as gpd
                except Exception as exc:
                    print(f"{name} vector source requires geopandas for {suffix}: {exc}")
                    return None
                frame = gpd.read_file(path)
                return json.loads(frame.to_json())
            print(f"Unsupported {name} vector file type: {path}")
            return None
        if url:
            cache_path = CACHE_DIR / f"vector_{re.sub(r'[^a-zA-Z0-9_]+', '_', name).strip('_')}.geojson"
            if cache_path.exists():
                startup_progress_message(f"讀取向量快取：{cache_path.name}")
                record_data_fetch_event("vector", name, "cache-hit", source=url, cache_path=str(cache_path), message="using cached vector geojson")
                return json.loads(cache_path.read_text(encoding="utf-8"))
            startup_progress_begin(f"下載向量圖層：{name}", None)
            text = read_url_text(url, timeout=90.0, progress_label=f"vector:{name}")
            cache_path.write_text(text, encoding="utf-8")
            record_data_fetch_event("vector", name, "cache-write", source=url, cache_path=str(cache_path), message="vector geojson cached", bytes_read=len(text.encode("utf-8", errors="replace")))
            startup_progress_done(f"{name} 向量圖層下載完成")
            return json.loads(text)
        if natural_earth_layer:
            path = natural_earth_geojson_path(natural_earth_source, natural_earth_layer)
            if not path.exists():
                record_data_fetch_event("naturalearth", name, "download-needed", source=f"{natural_earth_source}:{natural_earth_layer}", cache_path=str(path), message="Natural Earth cache missing")
                download_natural_earth_geojson(path, natural_earth_source, natural_earth_layer)
            else:
                record_data_fetch_event("naturalearth", name, "cache-hit", source=f"{natural_earth_source}:{natural_earth_layer}", cache_path=str(path), message="using Natural Earth cache")
            return json.loads(path.read_text(encoding="utf-8"))
    except Exception as exc:
        print(f"{name} vector layer unavailable: {exc}")
    return None


def _append_geojson_geometry_lines(geometry: dict | None, out: list[np.ndarray]) -> None:
    if not geometry:
        return
    gtype = geometry.get("type")
    coords = geometry.get("coordinates")
    if not coords:
        return
    if gtype == "LineString":
        arr = np.asarray(coords, dtype=np.float32)
        if arr.ndim == 2 and arr.shape[0] >= 2:
            out.append(arr[:, :2])
    elif gtype == "MultiLineString":
        for line in coords:
            arr = np.asarray(line, dtype=np.float32)
            if arr.ndim == 2 and arr.shape[0] >= 2:
                out.append(arr[:, :2])
    elif gtype == "Polygon":
        for ring in coords:
            arr = np.asarray(ring, dtype=np.float32)
            if arr.ndim == 2 and arr.shape[0] >= 2:
                out.append(arr[:, :2])
    elif gtype == "MultiPolygon":
        for polygon in coords:
            for ring in polygon:
                arr = np.asarray(ring, dtype=np.float32)
                if arr.ndim == 2 and arr.shape[0] >= 2:
                    out.append(arr[:, :2])
    elif gtype == "GeometryCollection":
        for geom in geometry.get("geometries", []):
            _append_geojson_geometry_lines(geom, out)


def vector_feature_identity(properties: dict | None, feature_index: int | None = None) -> dict[str, object]:
    props = properties if isinstance(properties, dict) else {}
    preview_keys = (
        "name",
        "NAME",
        "Name",
        "geoname",
        "GEONAME",
        "brk_name",
        "BRK_NAME",
        "territory",
        "TERRITORY",
        "territory1",
        "TERRITORY1",
        "territory2",
        "TERRITORY2",
        "sovereignt",
        "SOVEREIGNT",
        "sovereign1",
        "SOVEREIGN1",
        "sovereign2",
        "SOVEREIGN2",
        "admin",
        "ADMIN",
        "geonunit",
        "GEONUNIT",
        "iso_a2",
        "ISO_A2",
        "iso_a3",
        "ISO_A3",
        "adm0_a3",
        "ADM0_A3",
        "iso_ter1",
        "ISO_TER1",
        "iso_ter2",
        "ISO_TER2",
        "mrgid_eez",
        "MRGID_EEZ",
        "featurecla",
        "FEATURECLA",
        "pol_type",
        "POL_TYPE",
        "poltype",
        "POLTYPE",
        "boundary",
        "BOUNDARY",
        "type",
        "TYPE",
        "mrgid",
        "MRGID",
        "id",
        "ID",
    )
    preview = {key: props[key] for key in preview_keys if key in props and props[key] not in (None, "")}
    label = None
    for key in (
        "name",
        "NAME",
        "Name",
        "geoname",
        "GEONAME",
        "territory",
        "TERRITORY",
        "territory1",
        "TERRITORY1",
        "admin",
        "ADMIN",
        "sovereignt",
        "SOVEREIGNT",
        "sovereign1",
        "SOVEREIGN1",
        "brk_name",
        "BRK_NAME",
        "mrgid_eez",
        "MRGID_EEZ",
        "mrgid",
        "MRGID",
    ):
        value = preview.get(key)
        if value not in (None, ""):
            label = str(value)
            break
    return {
        "feature_index": feature_index,
        "label": label or (f"feature-{feature_index}" if feature_index is not None else "feature"),
        "identity_source": "source_geojson_properties",
        "identity_keys": list(preview.keys()),
        "properties": preview,
    }


def _append_geojson_geometry_line_features(
    geometry: dict | None,
    out_lines: list[np.ndarray],
    out_features: list[dict[str, object]],
    feature_identity: dict[str, object],
) -> None:
    if not geometry:
        return
    gtype = geometry.get("type")
    coords = geometry.get("coordinates")
    if not coords:
        return

    def append_line(coords_value, geometry_type: str) -> None:
        arr = np.asarray(coords_value, dtype=np.float32)
        if arr.ndim == 2 and arr.shape[0] >= 2:
            out_lines.append(arr[:, :2])
            item = dict(feature_identity)
            item["geometry_type"] = geometry_type
            item["line_part_index"] = len(out_features)
            out_features.append(item)

    if gtype == "LineString":
        append_line(coords, "LineString")
    elif gtype == "MultiLineString":
        for line in coords:
            append_line(line, "MultiLineString")
    elif gtype == "Polygon":
        for ring in coords:
            append_line(ring, "Polygon")
    elif gtype == "MultiPolygon":
        for polygon in coords:
            for ring in polygon:
                append_line(ring, "MultiPolygon")
    elif gtype == "GeometryCollection":
        for geom in geometry.get("geometries", []):
            _append_geojson_geometry_line_features(geom, out_lines, out_features, feature_identity)


def geojson_to_line_features(obj: dict | None, decimate: int = 1) -> tuple[list[np.ndarray], list[dict[str, object]]]:
    if not obj:
        return [], []
    lines: list[np.ndarray] = []
    features: list[dict[str, object]] = []
    if obj.get("type") == "FeatureCollection":
        for feature_index, feature in enumerate(obj.get("features", [])):
            identity = vector_feature_identity(feature.get("properties"), feature_index)
            _append_geojson_geometry_line_features(feature.get("geometry"), lines, features, identity)
    elif obj.get("type") == "Feature":
        identity = vector_feature_identity(obj.get("properties"), 0)
        _append_geojson_geometry_line_features(obj.get("geometry"), lines, features, identity)
    else:
        identity = vector_feature_identity({}, None)
        _append_geojson_geometry_line_features(obj, lines, features, identity)
    step = max(1, int(decimate))
    if step <= 1:
        return lines, features
    decimated: list[np.ndarray] = []
    decimated_features: list[dict[str, object]] = []
    for line, feature in zip(lines, features):
        if len(line) <= 2:
            decimated.append(line)
        else:
            sampled = line[::step]
            if not np.array_equal(sampled[-1], line[-1]):
                sampled = np.vstack([sampled, line[-1]])
            decimated.append(np.ascontiguousarray(sampled))
        decimated_features.append(feature)
    return decimated, decimated_features


def geojson_to_lines(obj: dict | None, decimate: int = 1) -> list[np.ndarray]:
    lines, _features = geojson_to_line_features(obj, decimate=decimate)
    return lines


class GeoVectorLineOverlay:
    def __init__(self, width: int, height: int, lines: list[np.ndarray], name: str, line_features: list[dict[str, object]] | None = None):
        self.width = int(width)
        self.height = int(height)
        self.lines = lines
        self.name = name
        self.line_features = list(line_features or [])
        if len(self.line_features) < len(self.lines):
            self.line_features.extend({} for _ in range(len(self.lines) - len(self.line_features)))
        self.empty = np.zeros((height, width, 4), dtype=np.uint8)
        if not lines:
            print(f"{name} layer has no vector geometry loaded.")

    def line_feature(self, line_index: int | None) -> dict[str, object] | None:
        if line_index is None:
            return None
        if 0 <= int(line_index) < len(self.line_features):
            feature = self.line_features[int(line_index)]
            return dict(feature) if isinstance(feature, dict) else None
        return None

    def render(
        self,
        yaw: float,
        pitch: float,
        zoom: float,
        flip_longitude: bool,
        flip_latitude: bool,
        globe_mask: np.ndarray,
        color: tuple[int, int, int],
        opacity: float,
        line_width: int,
        highlight_line_index: int | None = None,
        highlight_phase: float = 0.0,
        point_stride: int = 1,
        highlight_color: tuple[int, int, int] | None = None,
        highlight_fill_color: tuple[int, int, int] | None = None,
        highlight_alpha_scale: float = 1.0,
        highlight_width_extra: int = 0,
    ) -> np.ndarray:
        if not self.lines:
            return self.empty.copy()
        if opacity <= 0.0 and highlight_line_index is None:
            return self.empty.copy()
        from PIL import Image, ImageDraw

        img = Image.new("RGBA", (self.width, self.height), (0, 0, 0, 0))
        draw = ImageDraw.Draw(img)
        rgba = (int(color[0]), int(color[1]), int(color[2]), int(255 * max(0.0, min(float(opacity), 1.0))))
        point_stride = max(1, int(point_stride))
        aspect = self.width / float(self.height)
        cy = math.cos(-yaw)
        sy = math.sin(-yaw)
        cp = math.cos(-pitch)
        sp = math.sin(-pitch)
        max_jump = max(self.width, self.height) * 0.35

        def draw_projected_line(line: np.ndarray, rgba_value: tuple[int, int, int, int], width_value: int) -> list[list[tuple[float, float]]]:
            segments: list[list[tuple[float, float]]] = []
            if len(line) < 2:
                return segments
            render_line = line
            if point_stride > 1 and len(render_line) > point_stride + 2:
                render_line = render_line[::point_stride]
                if not np.array_equal(render_line[-1], line[-1]):
                    render_line = np.vstack([render_line, line[-1]])
            lon = np.radians(render_line[:, 0].astype(np.float32))
            lat = np.radians(render_line[:, 1].astype(np.float32))
            if flip_longitude:
                lon = -lon
            if flip_latitude:
                lat = -lat
            cos_lat = np.cos(lat)
            x = cos_lat * np.sin(lon)
            y = np.sin(lat)
            z = cos_lat * np.cos(lon)
            x1 = cy * x + sy * z
            y1 = y
            z1 = -sy * x + cy * z
            x2 = x1
            y2 = cp * y1 - sp * z1
            z2 = sp * y1 + cp * z1
            visible = z2 > 0.006
            sx = ((x2 / (float(zoom) * aspect)) + 1.0) * 0.5 * self.width
            sy2 = (1.0 - ((y2 / float(zoom)) + 1.0) * 0.5) * self.height
            segment: list[tuple[float, float]] = []
            last_point: tuple[float, float] | None = None
            for idx in range(len(render_line)):
                if not visible[idx]:
                    if len(segment) >= 2:
                        draw.line(segment, fill=rgba_value, width=max(1, int(width_value)), joint="curve")
                        segments.append(segment)
                    segment = []
                    last_point = None
                    continue
                point = (float(sx[idx]), float(sy2[idx]))
                if last_point is not None:
                    if abs(point[0] - last_point[0]) > max_jump or abs(point[1] - last_point[1]) > max_jump:
                        if len(segment) >= 2:
                            draw.line(segment, fill=rgba_value, width=max(1, int(width_value)), joint="curve")
                            segments.append(segment)
                        segment = []
                segment.append(point)
                last_point = point
            if len(segment) >= 2:
                draw.line(segment, fill=rgba_value, width=max(1, int(width_value)), joint="curve")
                segments.append(segment)
            return segments

        def screen_polygon_area(points: list[tuple[float, float]]) -> float:
            if len(points) < 3:
                return 0.0
            area = 0.0
            for idx, point in enumerate(points):
                next_point = points[(idx + 1) % len(points)]
                area += point[0] * next_point[1] - next_point[0] * point[1]
            return abs(area) * 0.5

        for line_index, line in enumerate(self.lines):
            if len(line) < 2:
                continue
            if highlight_line_index is not None and line_index == int(highlight_line_index):
                pulse = 0.5 + 0.5 * math.sin(float(highlight_phase) * math.tau)
                color_base = highlight_color or (255, 255, 180)
                alpha_scale = max(0.0, min(float(highlight_alpha_scale), 2.0))
                try:
                    line_closed = bool(np.linalg.norm(line[0] - line[-1]) < 1e-3)
                except Exception:
                    line_closed = False
                if line_closed:
                    fill_base = highlight_fill_color or color_base
                    fill_alpha = int(min(180, (32 + 42 * pulse) * alpha_scale))
                    fill_rgba = (int(fill_base[0]), int(fill_base[1]), int(fill_base[2]), fill_alpha)
                    fill_segments = draw_projected_line(line, (0, 0, 0, 0), 1)
                    for segment in fill_segments:
                        if len(segment) >= 3 and screen_polygon_area(segment) >= 6.0:
                            draw.polygon(segment, fill=fill_rgba)
                glow_alpha = int(min(255, (95 + 95 * pulse) * alpha_scale))
                core_alpha = int(min(255, 220 + 35 * alpha_scale))
                glow_width = max(4, int(line_width) + int(7 + 5 * pulse) + max(0, int(highlight_width_extra)))
                core_width = max(2, int(line_width) + 2 + max(0, int(highlight_width_extra // 4)))
                glow_rgba = (int(color_base[0]), int(color_base[1]), int(color_base[2]), glow_alpha)
                core_rgba = (
                    min(255, int(color_base[0]) + 32),
                    min(255, int(color_base[1]) + 32),
                    min(255, int(color_base[2]) + 32),
                    core_alpha,
                )
                draw_projected_line(line, glow_rgba, glow_width)
                draw_projected_line(line, core_rgba, core_width)
            else:
                draw_projected_line(line, rgba, max(1, int(line_width)))

        return mask_overlay_to_globe(np.asarray(img, dtype=np.uint8), globe_mask)

    def render_highlight(
        self,
        yaw: float,
        pitch: float,
        zoom: float,
        flip_longitude: bool,
        flip_latitude: bool,
        globe_mask: np.ndarray,
        line_index: int | None,
        highlight_phase: float = 0.0,
        line_width: int = 2,
    ) -> np.ndarray:
        if line_index is None or line_index < 0 or line_index >= len(self.lines):
            return self.empty.copy()
        return self.render(
            yaw,
            pitch,
            zoom,
            flip_longitude,
            flip_latitude,
            globe_mask,
            (0, 0, 0),
            0.0,
            max(1, int(line_width)),
            int(line_index),
            highlight_phase,
        )

    def hit_test(
        self,
        screen_x: float,
        screen_y: float,
        yaw: float,
        pitch: float,
        zoom: float,
        flip_longitude: bool,
        flip_latitude: bool,
        radius_px: float,
    ) -> dict | None:
        if not self.lines:
            return None
        aspect = self.width / float(self.height)
        cy = math.cos(-yaw)
        sy = math.sin(-yaw)
        cp = math.cos(-pitch)
        sp = math.sin(-pitch)
        best: dict | None = None
        best_d2 = float(radius_px) * float(radius_px)

        for line_index, line in enumerate(self.lines):
            if len(line) < 2:
                continue
            lon = np.radians(line[:, 0].astype(np.float32))
            lat = np.radians(line[:, 1].astype(np.float32))
            if flip_longitude:
                lon = -lon
            if flip_latitude:
                lat = -lat
            cos_lat = np.cos(lat)
            x = cos_lat * np.sin(lon)
            y = np.sin(lat)
            z = cos_lat * np.cos(lon)
            x1 = cy * x + sy * z
            y1 = y
            z1 = -sy * x + cy * z
            x2 = x1
            y2 = cp * y1 - sp * z1
            z2 = sp * y1 + cp * z1
            visible = z2 > 0.006
            if np.count_nonzero(visible) < 2:
                continue
            sx = ((x2 / (float(zoom) * aspect)) + 1.0) * 0.5 * self.width
            sy2 = (1.0 - ((y2 / float(zoom)) + 1.0) * 0.5) * self.height
            max_jump = max(self.width, self.height) * 0.35

            for idx in range(len(line) - 1):
                if not (visible[idx] and visible[idx + 1]):
                    continue
                x0 = float(sx[idx])
                y0 = float(sy2[idx])
                x1p = float(sx[idx + 1])
                y1p = float(sy2[idx + 1])
                if abs(x1p - x0) > max_jump or abs(y1p - y0) > max_jump:
                    continue
                vx = x1p - x0
                vy = y1p - y0
                seg_len2 = vx * vx + vy * vy
                if seg_len2 <= 1e-6:
                    continue
                t = max(0.0, min(1.0, ((float(screen_x) - x0) * vx + (float(screen_y) - y0) * vy) / seg_len2))
                px = x0 + vx * t
                py = y0 + vy * t
                dx = float(screen_x) - px
                dy = float(screen_y) - py
                d2 = dx * dx + dy * dy
                if d2 < best_d2:
                    best_d2 = d2
                    best = {
                        "line_index": line_index,
                        "distance_px": math.sqrt(d2),
                        "screen_x": px,
                        "screen_y": py,
                    }
                    feature = self.line_feature(line_index)
                    if feature:
                        best["feature"] = feature
        return best

    def area_hit_test(
        self,
        screen_x: float,
        screen_y: float,
        yaw: float,
        pitch: float,
        zoom: float,
        flip_longitude: bool,
        flip_latitude: bool,
    ) -> dict | None:
        if not self.lines:
            return None
        aspect = self.width / float(self.height)
        cy = math.cos(-yaw)
        sy = math.sin(-yaw)
        cp = math.cos(-pitch)
        sp = math.sin(-pitch)
        max_jump = max(self.width, self.height) * 0.35
        best: dict | None = None
        best_area = float("inf")

        def screen_polygon_area(points: list[tuple[float, float]]) -> float:
            if len(points) < 3:
                return 0.0
            area = 0.0
            for idx, point in enumerate(points):
                next_point = points[(idx + 1) % len(points)]
                area += point[0] * next_point[1] - next_point[0] * point[1]
            return abs(area) * 0.5

        def point_in_polygon(point_x: float, point_y: float, points: list[tuple[float, float]]) -> bool:
            inside = False
            count = len(points)
            if count < 3:
                return False
            prev_x, prev_y = points[-1]
            for next_x, next_y in points:
                crosses = (next_y > point_y) != (prev_y > point_y)
                if crosses:
                    denominator = prev_y - next_y
                    if abs(denominator) < 1e-9:
                        continue
                    x_at_y = (prev_x - next_x) * (point_y - next_y) / denominator + next_x
                    if point_x < x_at_y:
                        inside = not inside
                prev_x, prev_y = next_x, next_y
            return inside

        for line_index, line in enumerate(self.lines):
            if len(line) < 4:
                continue
            try:
                line_closed = bool(np.linalg.norm(line[0] - line[-1]) < 1e-3)
            except Exception:
                line_closed = False
            if not line_closed:
                continue
            lon = np.radians(line[:, 0].astype(np.float32))
            lat = np.radians(line[:, 1].astype(np.float32))
            if flip_longitude:
                lon = -lon
            if flip_latitude:
                lat = -lat
            cos_lat = np.cos(lat)
            x = cos_lat * np.sin(lon)
            y = np.sin(lat)
            z = cos_lat * np.cos(lon)
            x1 = cy * x + sy * z
            y1 = y
            z1 = -sy * x + cy * z
            x2 = x1
            y2 = cp * y1 - sp * z1
            z2 = sp * y1 + cp * z1
            visible = z2 > 0.006
            if not bool(np.all(visible)):
                continue
            sx = ((x2 / (float(zoom) * aspect)) + 1.0) * 0.5 * self.width
            sy2 = (1.0 - ((y2 / float(zoom)) + 1.0) * 0.5) * self.height
            points = [(float(sx[idx]), float(sy2[idx])) for idx in range(len(line))]
            if any(
                abs(points[idx][0] - points[idx - 1][0]) > max_jump
                or abs(points[idx][1] - points[idx - 1][1]) > max_jump
                for idx in range(1, len(points))
            ):
                continue
            area = screen_polygon_area(points)
            if area < 8.0 or area >= best_area:
                continue
            if not point_in_polygon(float(screen_x), float(screen_y), points):
                continue
            best_area = area
            best = {
                "line_index": line_index,
                "distance_px": 0.0,
                "screen_x": float(screen_x),
                "screen_y": float(screen_y),
                "area_px2": area,
                "hit_kind": "closed_ring_area",
            }
            feature = self.line_feature(line_index)
            if feature:
                best["feature"] = feature
        return best



