    def _load_hydrology_overlays(self) -> dict[str, GeoVectorLineOverlay]:
        overlays: dict[str, GeoVectorLineOverlay] = {}
        for layer_id, spec in HYDROLOGY_SPECS.items():
            overlays[layer_id] = self._load_single_hydrology_overlay(layer_id)
        return overlays

    def _load_single_hydrology_overlay(self, layer_id: str) -> GeoVectorLineOverlay:
        spec = HYDROLOGY_SPECS[layer_id]
        prefix = spec["prefix"]
        decision = self.hydrology_lod_policy.decision(self.basemap_lod, layer_id)
        render_profile = self.hydrology_render_profile.decision(self.basemap_lod, layer_id)
        obj = load_vector_geojson_from_source(
            layer_id,
            file_path=decision["file_path"],
            url=decision["url"],
            natural_earth_layer=decision["natural_earth_layer"],
            natural_earth_source=decision["natural_earth_source"],
        )
        lines, features = geojson_to_line_features(obj, decimate=max(1, int(render_profile["decimate"])))
        return GeoVectorLineOverlay(self.width, self.height, lines, spec["name"], features)

    def _load_boundary_overlays(self) -> dict[str, GeoVectorLineOverlay]:
        overlays: dict[str, GeoVectorLineOverlay] = {}
        for layer_id, spec in BOUNDARY_SPECS.items():
            if self.layer_visible.get(layer_id, False):
                overlays[layer_id] = self._load_single_boundary_overlay(layer_id)
            else:
                overlays[layer_id] = GeoVectorLineOverlay(self.width, self.height, [], spec["name"])
        return overlays

    def _load_single_boundary_overlay(self, layer_id: str) -> GeoVectorLineOverlay:
        spec = BOUNDARY_SPECS[layer_id]
        decision = self.boundary_lod_policy.decision(self.basemap_lod, layer_id)
        obj = load_vector_geojson_from_source(
            layer_id,
            file_path=decision["file_path"],
            url=decision["url"],
            natural_earth_layer=decision["natural_earth_layer"],
            natural_earth_source=decision["natural_earth_source"],
        )
        lines, features = geojson_to_line_features(obj, decimate=max(1, int(decision["decimate"])))
        return GeoVectorLineOverlay(self.width, self.height, lines, spec["name"], features)

    def _vector_cache_limit(self) -> int:
        megapixels = max(1.0, (int(self.width) * int(self.height)) / 1_000_000.0)
        if megapixels >= 6.0:
            return 2
        if megapixels >= 3.0:
            return 3
        return 5

    def _vector_point_stride(self) -> int:
        budget = self.render_budget_decision()
        return max(1, int(budget.get("vector_point_stride", 1)))

    def _vector_camera_key(self, namespace: str) -> tuple:
        budget = self.render_budget_decision()
        q_rad = max(math.radians(0.001), math.radians(float(budget.get("vector_cache_degrees", 0.004))))
        q_zoom = max(0.0005, float(budget.get("vector_cache_zoom_step", 0.001)))
        return (
            namespace,
            int(self.width),
            int(self.height),
            int(round(float(self.yaw) / q_rad)),
            int(round(float(self.pitch) / q_rad)),
            int(round(float(self.zoom) / q_zoom)),
            bool(self.flip_longitude),
            bool(self.flip_latitude),
            self.basemap_lod,
            self._vector_point_stride(),
        )

    def _cache_vector_overlay(self, cache_key: tuple, payload: object) -> None:
        self.vector_overlay_cache[cache_key] = payload
        if cache_key in self.vector_overlay_cache_order:
            self.vector_overlay_cache_order.remove(cache_key)
        self.vector_overlay_cache_order.append(cache_key)
        limit = self._vector_cache_limit()
        while len(self.vector_overlay_cache_order) > limit:
            old_key = self.vector_overlay_cache_order.pop(0)
            self.vector_overlay_cache.pop(old_key, None)

    def _lookup_vector_overlay_cache(self, cache_key: tuple) -> object | None:
        cached = self.vector_overlay_cache.get(cache_key)
        if cached is None:
            self.vector_overlay_cache_misses += 1
            return None
        self.vector_overlay_cache_hits += 1
        if cache_key in self.vector_overlay_cache_order:
            self.vector_overlay_cache_order.remove(cache_key)
        self.vector_overlay_cache_order.append(cache_key)
        return cached

    def _current_hydrology_view_key(self) -> tuple:
        layer_state = tuple(
            (
                layer_id,
                bool(self.layer_visible.get(layer_id, True)),
                id(self.hydrology_overlays.get(layer_id)),
                self.hydrology_render_profile.decision(self.basemap_lod, layer_id)["decimate"],
                round(float(self.hydrology_render_profile.decision(self.basemap_lod, layer_id)["opacity_scale"]), 3),
                round(float(self.hydrology_render_profile.decision(self.basemap_lod, layer_id)["width_scale"]), 3),
                round(float(getattr(self.args, f"{HYDROLOGY_SPECS[layer_id]['prefix']}_opacity", 0.55)), 3),
                round(float(getattr(self.args, f"{HYDROLOGY_SPECS[layer_id]['prefix']}_width", 1)), 3),
            )
            for layer_id in ("lakes", "rivers")
        )
        return self._vector_camera_key("hydrology") + (
            layer_state,
            style_vector_cache_key(getattr(self.args, "style_profile", "scientific")),
        )

    def _current_boundary_view_key(self) -> tuple:
        boundary_highlight = getattr(self, "boundary_highlight_state", {})
        breathing = boundary_highlight.get("breathing", {}) if isinstance(boundary_highlight, dict) else {}
        highlight_key = (
            bool(boundary_highlight.get("enabled", False)) if isinstance(boundary_highlight, dict) else False,
            boundary_highlight.get("trigger", "hover") if isinstance(boundary_highlight, dict) else "hover",
            tuple(boundary_highlight.get("renderer_target_layers", [])) if isinstance(boundary_highlight, dict) else (),
            tuple(boundary_highlight.get("color_rgb", [])) if isinstance(boundary_highlight, dict) else (),
            boundary_highlight.get("contrast", 45) if isinstance(boundary_highlight, dict) else 45,
            boundary_highlight.get("gamma", 100) if isinstance(boundary_highlight, dict) else 100,
            boundary_highlight.get("alpha", 48) if isinstance(boundary_highlight, dict) else 48,
            boundary_highlight.get("feather", 14) if isinstance(boundary_highlight, dict) else 14,
            bool(breathing.get("enabled", True)) if isinstance(breathing, dict) else True,
            breathing.get("speed", 42) if isinstance(breathing, dict) else 42,
            breathing.get("amplitude", 16) if isinstance(breathing, dict) else 16,
        )
        layer_state = tuple(
            (
                layer_id,
                bool(self.layer_visible.get(layer_id, True)),
                id(self.boundary_overlays.get(layer_id)),
                round(float(getattr(self.args, {
                    "borders": "border_opacity",
                    "territorial_sea": "territorial_sea_opacity",
                    "eez": "eez_opacity",
                    "high_seas": "high_seas_opacity",
                }.get(layer_id, f"{layer_id}_opacity"), 0.65)), 3),
                int(getattr(self.args, {
                    "borders": "border_width",
                    "territorial_sea": "territorial_sea_width",
                    "eez": "eez_width",
                    "high_seas": "high_seas_width",
                }.get(layer_id, f"{layer_id}_width"), 1)),
            )
            for layer_id in BOUNDARY_SPECS
        )
        return self._vector_camera_key("boundary") + (
            layer_state,
            style_vector_cache_key(getattr(self.args, "style_profile", "scientific")),
            self.hover_boundary_hit.get("layer_id"),
            self.hover_boundary_hit.get("line_index"),
            self.boundary_hover_phase_bucket,
            highlight_key,
        )

    def _render_hydrology_if_needed(self, force: bool = False) -> None:
        view_key = self._current_hydrology_view_key()
        if not force and not self.hydrology_dirty and self.hydrology_view_key == view_key:
            return
        cache_key = ("hydrology", view_key)
        cached = None if force else self._lookup_vector_overlay_cache(cache_key)
        if cached is not None:
            self.lake_overlay_rgba, self.river_overlay_rgba = cached
            self.hydrology_view_key = view_key
            self.hydrology_dirty = False
            return
        for layer_id, attr in (("lakes", "lake_overlay_rgba"), ("rivers", "river_overlay_rgba")):
            overlay = self.hydrology_overlays.get(layer_id)
            if overlay is None or not self.layer_visible.get(layer_id, True):
                setattr(self, attr, np.zeros_like(self.globe_rgba))
                continue
            spec = HYDROLOGY_SPECS[layer_id]
            render_profile = self.hydrology_render_profile.decision(self.basemap_lod, layer_id)
            render_params = build_hydrology_render_params(
                self.args,
                layer_id,
                spec,
                render_profile,
                getattr(self.args, "style_profile", "scientific"),
            )
            setattr(
                self,
                attr,
                overlay.render(
                    self.yaw,
                    self.pitch,
                    self.zoom,
                    self.flip_longitude,
                    self.flip_latitude,
                    self.globe_mask,
                    render_params["color"],
                    render_params["opacity"],
                    render_params["width"],
                    point_stride=self._vector_point_stride(),
                ),
            )
        self.hydrology_view_key = view_key
        self.hydrology_dirty = False
        self._cache_vector_overlay(cache_key, (self.lake_overlay_rgba, self.river_overlay_rgba))

    def _render_boundaries_if_needed(self, force: bool = False) -> None:
        view_key = self._current_boundary_view_key()
        if not force and not self.boundary_dirty and self.boundary_view_key == view_key:
            return
        cache_key = ("boundary", view_key)
        cached = None if force else self._lookup_vector_overlay_cache(cache_key)
        if cached is not None:
            if isinstance(cached, tuple) and len(cached) == 2:
                self.boundary_overlay_rgba, self.boundary_layer_rgba = cached
            else:
                self.boundary_overlay_rgba = cached
                self.boundary_layer_rgba = {}
            self.boundary_view_key = view_key
            self.boundary_dirty = False
            self.boundary_hover_dirty = False
            return
        composite = np.zeros_like(self.globe_rgba)
        layer_rgba: dict[str, np.ndarray] = {}
        boundary_highlight = getattr(self, "boundary_highlight_state", {})
        highlight_enabled = bool(boundary_highlight.get("enabled", False)) if isinstance(boundary_highlight, dict) else False
        highlight_trigger = str(boundary_highlight.get("trigger", "hover")) if isinstance(boundary_highlight, dict) else "hover"
        highlight_targets = set(boundary_highlight.get("renderer_target_layers", [])) if isinstance(boundary_highlight, dict) else set()
        highlight_layer = self.hover_boundary_hit.get("layer_id") if highlight_enabled and highlight_trigger in {"hover", "hover_or_selected"} else None
        if highlight_layer not in highlight_targets:
            highlight_layer = None
        highlight_line_index = self.hover_boundary_hit.get("line_index") if highlight_layer is not None else None
        highlight_color = apply_boundary_highlight_color_controls(
            boundary_highlight.get("color_rgb", [255, 190, 72]) if isinstance(boundary_highlight, dict) else [255, 190, 72],
            boundary_highlight.get("contrast", 45) if isinstance(boundary_highlight, dict) else 45,
            boundary_highlight.get("gamma", 100) if isinstance(boundary_highlight, dict) else 100,
        )
        highlight_fill_color = apply_boundary_highlight_fill_controls(
            boundary_highlight.get("color_rgb", [255, 190, 72]) if isinstance(boundary_highlight, dict) else [255, 190, 72],
            boundary_highlight.get("contrast", 45) if isinstance(boundary_highlight, dict) else 45,
            boundary_highlight.get("gamma", 100) if isinstance(boundary_highlight, dict) else 100,
        )
        highlight_alpha_scale = (
            max(0.0, min(_clamp_int_value(boundary_highlight.get("alpha"), 48, 0, 100) / 48.0, 2.0))
            if isinstance(boundary_highlight, dict)
            else 1.0
        )
        highlight_width_extra = int(_clamp_int_value(boundary_highlight.get("feather"), 14, 0, 100) / 10)
        breathing = boundary_highlight.get("breathing", {}) if isinstance(boundary_highlight, dict) else {}
        breath_enabled = bool(breathing.get("enabled", True)) if isinstance(breathing, dict) else True
        breath_speed = _clamp_int_value(breathing.get("speed"), 42, 0, 100) if isinstance(breathing, dict) else 42
        if breath_enabled:
            highlight_phase = (time.time() * max(0.05, breath_speed / 50.0)) % 1.0
        else:
            highlight_phase = 0.25
        for layer_id, spec in BOUNDARY_SPECS.items():
            overlay = self.boundary_overlays.get(layer_id)
            if overlay is None or not self.layer_visible.get(layer_id, True):
                continue
            render_params = build_boundary_render_params(
                self.args,
                layer_id,
                spec,
                getattr(self.args, "style_profile", "scientific"),
            )
            rendered = overlay.render(
                self.yaw,
                self.pitch,
                self.zoom,
                self.flip_longitude,
                self.flip_latitude,
                self.globe_mask,
                render_params["color"],
                render_params["opacity"],
                render_params["width"],
                int(highlight_line_index) if highlight_layer == layer_id and highlight_line_index is not None else None,
                highlight_phase,
                point_stride=self._vector_point_stride(),
                highlight_color=highlight_color,
                highlight_fill_color=highlight_fill_color,
                highlight_alpha_scale=highlight_alpha_scale,
                highlight_width_extra=highlight_width_extra,
            )
            layer_rgba[layer_id] = rendered
            composite = alpha_compose_transparent(composite, rendered)
        self.boundary_overlay_rgba = composite
        self.boundary_layer_rgba = layer_rgba
        self.boundary_view_key = view_key
        self.boundary_dirty = False
        self.boundary_hover_dirty = False
        self._cache_vector_overlay(cache_key, (self.boundary_overlay_rgba, self.boundary_layer_rgba))

    def hydrology_layer_status_text(self, layer_id: str) -> str:
        overlay = self.hydrology_overlays.get(layer_id)
        count = len(getattr(overlay, "lines", [])) if overlay else 0
        decision = self.hydrology_lod_policy.decision(self.basemap_lod, layer_id)
        render_profile = self.hydrology_render_profile.decision(self.basemap_lod, layer_id)
        strictness = self.hydrology_strictness_policy.decision(self.basemap_lod, layer_id, decision)
        return (
            f"{layer_id}: {count:,} lines; provider={decision['provider_id']}; "
            f"source={decision['natural_earth_source']}; input={decision['renderer_input']}; "
            f"decimate={render_profile['decimate']}; strictness={strictness['tier']}; {decision['status']}"
        )

    def hydrology_provider_decisions_text(self) -> str:
        lines = [f"Hydrology provider decisions for LOD={self.basemap_lod}"]
        for layer_id in HYDROLOGY_SPECS:
            decision = self.hydrology_lod_policy.decision(self.basemap_lod, layer_id)
            render_profile = self.hydrology_render_profile.decision(self.basemap_lod, layer_id)
            strictness = self.hydrology_strictness_policy.decision(self.basemap_lod, layer_id, decision)
            manifest = decision["manifest"]
            lines.append(f"- {layer_id}: {decision['provider_id']}")
            lines.append(f"  source: {manifest['source_url']}")
            lines.append(f"  adapter target: {decision['target_adapter']}")
            lines.append(f"  renderer input: {decision['renderer_input']}")
            lines.append(f"  render decimate: {render_profile['decimate']}")
            lines.append(f"  opacity/width scale: {render_profile['opacity_scale']:.2f}/{render_profile['width_scale']:.2f}")
            lines.append(f"  strictness: {strictness['tier']} ({strictness['scientific_use']})")
            if decision.get("strict_source", {}).get("configured"):
                strict_source = decision["strict_source"]
                lines.append(f"  strict provider: {strict_source['label']} ({strict_source['provider_id']})")
                lines.append(f"  strict metadata complete: {strict_source.get('metadata_complete', False)}")
                if strict_source.get("metadata_missing"):
                    lines.append(f"  strict metadata missing: {', '.join(strict_source['metadata_missing'])}")
            lines.append(f"  strictness next: {strictness['next_action']}")
            lines.append(f"  cache: {manifest['cache_path']}")
        return "\n".join(lines)

    def hydrology_control_snapshot(self) -> dict:
        layers = {}
        for layer_id, spec in HYDROLOGY_SPECS.items():
            prefix = spec["prefix"]
            overlay = self.hydrology_overlays.get(layer_id)
            decision = self.hydrology_lod_policy.decision(self.basemap_lod, layer_id)
            render_profile = self.hydrology_render_profile.decision(self.basemap_lod, layer_id)
            strictness = self.hydrology_strictness_policy.decision(self.basemap_lod, layer_id, decision)
            render_params = build_hydrology_render_params(
                self.args,
                layer_id,
                spec,
                render_profile,
                getattr(self.args, "style_profile", "scientific"),
            )
            layers[layer_id] = {
                "visible": bool(self.layer_visible.get(layer_id, True)),
                "line_count": int(len(getattr(overlay, "lines", []))) if overlay else 0,
                "source": decision,
                "render_profile": render_profile,
                "resolved_render_params": render_params,
                "strictness": strictness,
                "ui_controls": {
                    "file_attr": f"{prefix}_file",
                    "url_attr": f"{prefix}_url",
                    "opacity_attr": f"{prefix}_opacity",
                    "width_attr": f"{prefix}_width",
                    "layer_attr": f"{prefix}_layer",
                },
            }
        return {
            "contract": "Hydrology control owns source selection and vector simplification; GeoVectorLineOverlay only receives lon/lat lines plus screen-space render parameters.",
            "source_mode": getattr(self.args, "hydrology_source_mode", "lod"),
            "basemap_lod": self.basemap_lod,
            "render_lod_profile": {
                layer_id: self.hydrology_render_profile.decision(self.basemap_lod, layer_id)
                for layer_id in HYDROLOGY_SPECS
            },
            "layers": layers,
            "dirty": bool(self.hydrology_dirty),
            "view_key": self.hydrology_view_key,
            "vector_cache": {
                "items": len(self.vector_overlay_cache),
                "limit": self._vector_cache_limit(),
                "hits": self.vector_overlay_cache_hits,
                "misses": self.vector_overlay_cache_misses,
                "deferred": self.vector_overlay_cache_deferred,
            },
            "next_module_target": "data_sources/hydrology_provider.py + overlays/vector_lines.py",
        }

    def hydrology_control_text(self) -> str:
        return json.dumps(self.hydrology_control_snapshot(), ensure_ascii=False, indent=2, default=str)

    def hydrology_basic_readiness_matrix_snapshot(self) -> dict:
        style_profile = getattr(self.args, "style_profile", "scientific")
        layers = {}
        loaded_count = 0
        contract_ready_count = 0
        for layer_id, spec in HYDROLOGY_SPECS.items():
            prefix = spec["prefix"]
            overlay = self.hydrology_overlays.get(layer_id)
            line_count = int(len(getattr(overlay, "lines", []))) if overlay else 0
            decision = self.hydrology_lod_policy.decision(self.basemap_lod, layer_id)
            render_profile = self.hydrology_render_profile.decision(self.basemap_lod, layer_id)
            strictness = self.hydrology_strictness_policy.decision(self.basemap_lod, layer_id, decision)
            render_params = build_hydrology_render_params(
                self.args,
                layer_id,
                spec,
                render_profile,
                style_profile,
            )
            data_loaded = line_count > 0
            contract_ready = bool(
                decision.get("provider_id")
                and decision.get("renderer_input")
                and render_profile
                and strictness.get("tier")
                and render_params
            )
            visible = bool(self.layer_visible.get(layer_id, getattr(self.args, f"{prefix}_layer", True)))
            if data_loaded:
                loaded_count += 1
            if contract_ready:
                contract_ready_count += 1
            layers[layer_id] = {
                "name": spec.get("name", layer_id),
                "visible": visible,
                "data_loaded": data_loaded,
                "line_count": line_count,
                "contract_ready": contract_ready,
                "readiness": (
                    "disabled"
                    if not visible else
                    "ready_with_loaded_vectors"
                    if data_loaded else
                    "configured_waiting_for_vectors"
                ),
                "provider_id": decision.get("provider_id", ""),
                "provider_status": decision.get("status", ""),
                "renderer_input": decision.get("renderer_input", ""),
                "target_adapter": decision.get("target_adapter", ""),
                "strictness_tier": strictness.get("tier", ""),
                "strictness_next_action": strictness.get("next_action", ""),
                "render_profile": render_profile,
                "resolved_render_params": render_params,
                "ui_control_attrs": {
                    "file": f"{prefix}_file",
                    "url": f"{prefix}_url",
                    "opacity": f"{prefix}_opacity",
                    "width": f"{prefix}_width",
                    "layer": f"{prefix}_layer",
                },
            }
        return {
            "contract": "Hydrology basic readiness matrix separates static control readiness from runtime vector-data loading for lakes/rivers.",
            "basemap_lod": self.basemap_lod,
            "source_mode": getattr(self.args, "hydrology_source_mode", "lod"),
            "style_profile": style_profile,
            "layer_count": len(layers),
            "contract_ready_count": contract_ready_count,
            "loaded_count": loaded_count,
            "runtime_verification": "not-run",
            "layers": layers,
            "next_module_target": "data_sources/hydrology_provider.py + overlays/vector_lines.py",
        }

    def hydrology_basic_readiness_matrix_text(self) -> str:
        return json.dumps(self.hydrology_basic_readiness_matrix_snapshot(), ensure_ascii=False, indent=2, default=str)

    def hydrology_dirty_reload_contract_snapshot(self) -> dict:
        items = []
        for item in HYDROLOGY_DIRTY_RELOAD_CONTRACT:
            expected_flags = list(item["expected_dirty_flags"])
            missing_flags = [
                flag for flag in expected_flags
                if not hasattr(self, flag)
            ]
            current_flags = {
                flag: bool(getattr(self, flag, False))
                for flag in expected_flags
                if hasattr(self, flag)
            }
            entry = dict(item)
            entry["current_flags"] = current_flags
            entry["missing_flags"] = missing_flags
            entry["contract_ready"] = not missing_flags
            items.append(entry)
        missing_contracts = [
            item["trigger"] for item in items
            if not item["contract_ready"]
        ]
        return {
            "contract": "Hydrology dirty/reload contract keeps source reload, strict provider selection, render controls, and vector cache ownership explicit before splitting hydrology provider code.",
            "runtime_verification": "not-run",
            "basemap_lod": self.basemap_lod,
            "source_mode": getattr(self.args, "hydrology_source_mode", "lod"),
            "layer_count": len(HYDROLOGY_SPECS),
            "trigger_count": len(items),
            "ready": not missing_contracts,
            "missing_contracts": missing_contracts,
            "vector_cache": {
                "items": len(self.vector_overlay_cache),
                "limit": self._vector_cache_limit(),
                "hits": self.vector_overlay_cache_hits,
                "misses": self.vector_overlay_cache_misses,
                "deferred": self.vector_overlay_cache_deferred,
            },
            "items": items,
            "next_module_target": "data_sources/hydrology_provider.py + overlays/vector_lines.py",
        }

    def hydrology_dirty_reload_contract_text(self) -> str:
        return json.dumps(self.hydrology_dirty_reload_contract_snapshot(), ensure_ascii=False, indent=2, default=str)

    def reload_hydrology_layer(self, layer_id: str, file_path: str | None = None, url: str | None = None) -> None:
        if layer_id not in HYDROLOGY_SPECS:
            return
        prefix = HYDROLOGY_SPECS[layer_id]["prefix"]
        setattr(self.args, f"{prefix}_file", (file_path or "").strip() or None)
        setattr(self.args, f"{prefix}_url", (url or "").strip() or None)
        self.hydrology_overlays[layer_id] = self._load_single_hydrology_overlay(layer_id)
        self.hydrology_dirty = True
        self.overlay_dirty = True

    def set_hydrology_strict_source(self, layer_id: str, port_id: str, file_path: str | None = None, url: str | None = None) -> None:
        if layer_id not in HYDROLOGY_SPECS:
            return
        selected = None
        for port in HYDROLOGY_STRICT_PROVIDER_PORTS.get(layer_id, []):
            setattr(self.args, port["file_attr"], None)
            setattr(self.args, port["url_attr"], None)
            if port["id"] == port_id:
                selected = port
        if selected is None:
            return
        setattr(self.args, selected["file_attr"], (file_path or "").strip() or None)
        setattr(self.args, selected["url_attr"], (url or "").strip() or None)
        self.args.hydrology_source_mode = "strict"
        self.hydrology_overlays[layer_id] = self._load_single_hydrology_overlay(layer_id)
        self.hydrology_dirty = True
        self.overlay_dirty = True

    def set_hydrology_strict_metadata(
        self,
        source_version: str = "",
        license_text: str = "",
        projection: str = "",
        attribution: str = "",
        schema_note: str = "",
    ) -> None:
        self.args.hydrology_source_version = str(source_version or "")
        self.args.hydrology_license = str(license_text or "")
        self.args.hydrology_projection = str(projection or "")
        self.args.hydrology_attribution = str(attribution or "")
        self.args.hydrology_schema_note = str(schema_note or "")
        self.hydrology_dirty = True
        self.overlay_dirty = True

    def set_hydrology_source_mode(self, mode: str) -> None:
        mode = str(mode or "lod")
        if mode not in {"lod", "manual", "strict"}:
            mode = "lod"
        self.args.hydrology_source_mode = mode
        self.hydrology_dirty = True
        self.overlay_dirty = True

    def set_hydrology_opacity(self, layer_id: str, value: float) -> None:
        if layer_id not in HYDROLOGY_SPECS:
            return
        setattr(self.args, f"{HYDROLOGY_SPECS[layer_id]['prefix']}_opacity", max(0.0, min(float(value), 1.0)))
        self.hydrology_dirty = True
        self.overlay_dirty = True

    def set_hydrology_width(self, layer_id: str, value: int) -> None:
        if layer_id not in HYDROLOGY_SPECS:
            return
        setattr(self.args, f"{HYDROLOGY_SPECS[layer_id]['prefix']}_width", max(1, int(value)))
        self.hydrology_dirty = True
        self.overlay_dirty = True

    def layer_label(self, layer_id: str) -> str:
        return self.LAYER_LABELS.get(layer_id, HYDROLOGY_SPECS.get(layer_id, {}).get("name", layer_id))

    def set_layer_visible(self, layer_id: str, visible: bool) -> None:
        self.layer_visible[layer_id] = bool(visible)
        if layer_id == "grid":
            self.args.show_grid = bool(visible)
            self.globe_dirty = True
        if layer_id == "stars":
            self.args.show_stars = bool(visible)
            self.globe_dirty = True
        if layer_id in HYDROLOGY_SPECS:
            setattr(self.args, f"{HYDROLOGY_SPECS[layer_id]['prefix']}_layer", bool(visible))
            self.hydrology_dirty = True
        if layer_id in BOUNDARY_SPECS:
            overlay = getattr(self, "boundary_overlays", {}).get(layer_id)
            if bool(visible) and (overlay is None or not getattr(overlay, "lines", [])):
                self.boundary_overlays[layer_id] = self._load_single_boundary_overlay(layer_id)
            self.boundary_dirty = True
        if layer_id == "scale":
            self.args.scale_bar = bool(visible)
        if layer_id == "contours":
            self.args.terrain_contours = bool(visible)
            self.globe_dirty = True
        if layer_id == "ocean_material":
            self.args.ocean_material = bool(visible)
            self.globe_dirty = True
        if layer_id == "vehicle_icons":
            self.args.vehicle_icons = bool(visible)
        self.overlay_dirty = True
        self.globe_dirty = self.globe_dirty or layer_id in {"globe", "ice", "forest", "clouds", "contours", "grid", "stars", "ocean_material"}

    def set_layer_order(self, order: list[str]) -> None:
        known = [layer for layer in order if layer in self.LAYER_LABELS]
        for layer in self.layer_order:
            if layer not in known:
                known.append(layer)
        self.layer_order = known
        self.overlay_dirty = True

    def layer_allowed_in_mode(self, layer_id: str) -> bool:
        mode = str(getattr(self.args, "data_mode", "realtime"))
        if layer_id in {"ais", "aircraft", "vehicle_icons"}:
            return mode == "realtime"
        return True

    def mode_label(self, mode: str | None = None) -> str:
        mode = str(mode or getattr(self.args, "data_mode", "realtime"))
        return {
            "static": "Static mode",
            "timeseries": "Time-series mode",
            "realtime": "Realtime mode",
        }.get(mode, mode)

    def selected_info_text(self) -> str:
        if self.selected_pin_hit is not None:
            return self.pin_hit_info_text(self.selected_pin_hit, "Selected Pin")
        if self.selected_boundary_hit.get("layer_id"):
            return self.boundary_hit_info_text(self.selected_boundary_hit, "Selected Boundary")
        if self.selected_hydrology_hit.get("layer_id"):
            return self.boundary_hit_info_text(self.selected_hydrology_hit, "Selected Hydrology")
        if self.hover_pin_hit is not None:
            return self.pin_hit_info_text(self.hover_pin_hit, "Hover Pin")
        if self.selected_vehicle is None:
            result = getattr(self, "last_layer_pick_result", {})
            if isinstance(result, dict) and result.get("event") not in {None, "none"}:
                return "\n".join(
                    [
                        "Selected layer pick",
                        f"- event: {result.get('event')}",
                        f"- renderer_layer: {result.get('renderer_layer')}",
                        f"- picker: {result.get('picker')}",
                        f"- hit: {result.get('hit')}",
                    ]
                )
            return "No selected object."
        row = self.selected_vehicle
        if isinstance(row, pd.Series):
            lines = ["Selected vehicle"]
            for key in ("source", "mmsi", "icao24", "name", "shipname", "callsign", "lat", "lon", "sog", "speed_kt", "altitude_m", "cog", "heading", "timestamp"):
                if key in row and pd.notna(row.get(key)):
                    lines.append(f"- {key}: {row.get(key)}")
            return "\n".join(lines)
        return str(row)

    def pin_hit_info_text(self, hit: dict[str, object], title: str) -> str:
        lines = [title]
        for key in ("id", "type", "label", "latitude", "longitude", "label_priority", "occlusion"):
            value = hit.get(key)
            if value is not None:
                lines.append(f"- {key}: {value}")
        if "screen_x" in hit and "screen_y" in hit:
            lines.append(f"- screen: {float(hit['screen_x']):.1f}, {float(hit['screen_y']):.1f}")
        if "pick_distance_px" in hit:
            lines.append(f"- pick_distance_px: {float(hit['pick_distance_px']):.1f}")
        return "\n".join(lines)

    def boundary_hit_info_text(self, hit: dict[str, object], title: str) -> str:
        lines = [title]
        for key in ("layer_id", "name", "line_index", "distance_px"):
            value = hit.get(key)
            if value is not None:
                lines.append(f"- {key}: {value}")
        feature = hit.get("feature")
        if isinstance(feature, dict):
            if feature.get("label") is not None:
                lines.append(f"- feature: {feature.get('label')}")
            properties = feature.get("properties")
            if isinstance(properties, dict) and properties:
                preview = ", ".join(f"{key}={value}" for key, value in list(properties.items())[:4])
                lines.append(f"- feature_properties: {preview}")
        return "\n".join(lines)

    def write_pin_pick_state(self, event_kind: str, hit: dict[str, object] | None = None) -> None:
        if self.pin_pick_state_file is None:
            return
        payload = {
            "schema": "rrkal_displaytools.renderer_pin_pick_state.v1",
            "updated_at_utc": datetime.datetime.now(datetime.timezone.utc).isoformat(),
            "event": event_kind,
            "selected_pin_id": self.selected_pin_id,
            "selected_pin": self.selected_pin_hit,
            "hover_pin": self.hover_pin_hit,
            "event_pin": hit,
            "pin_visible_count": self.pin_visible_count,
            "frame_index": self.frame_index,
            "source": "taichi_global_bathymetry",
        }
        try:
            self.pin_pick_state_file.parent.mkdir(parents=True, exist_ok=True)
            self.pin_pick_state_file.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
        except OSError as exc:
            print(f"Unable to write pin pick state: {exc}")

    def selected_vehicle_summary(self) -> dict[str, object] | None:
        row = self.selected_vehicle
        if not isinstance(row, pd.Series):
            return None
        summary: dict[str, object] = {}
        for key in ("source", "mmsi", "icao24", "name", "shipname", "callsign", "lat", "lon", "sog", "speed_kt", "altitude_m", "cog", "heading", "timestamp"):
            if key in row and pd.notna(row.get(key)):
                summary[key] = str(row.get(key))
        return summary

    def write_layer_pick_state(self) -> None:
        if self.layer_pick_state_file is None:
            return
        payload = {
            "schema": "rrkal_displaytools.renderer_layer_pick_state.v1",
            "updated_at_utc": datetime.datetime.now(datetime.timezone.utc).isoformat(),
            "event": self.last_layer_pick_result.get("event"),
            "selected_renderer_layer": self.selected_renderer_layer_id,
            "selected_layer_semantic_target": self.selected_layer_semantic_target,
            "screen_position": self.last_layer_pick_screen,
            "pick_result": self.last_layer_pick_result,
            "selected_pin_id": self.selected_pin_id,
            "selected_pin": self.selected_pin_hit,
            "selected_vehicle": self.selected_vehicle_summary(),
            "selected_boundary": self.selected_boundary_hit if self.selected_boundary_hit.get("layer_id") else None,
            "selected_hydrology": self.selected_hydrology_hit if self.selected_hydrology_hit.get("layer_id") else None,
            "frame_index": self.frame_index,
            "source": "taichi_global_bathymetry",
        }
        try:
            self.layer_pick_state_file.parent.mkdir(parents=True, exist_ok=True)
            self.layer_pick_state_file.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
        except OSError as exc:
            print(f"Unable to write layer pick state: {exc}")

    def layer_render_plan_runtime_snapshot(
        self,
        changed: bool | None = None,
        force: bool = False,
        defer_vector_overlays: bool | None = None,
    ) -> dict[str, object]:
        visible_layers = [layer_id for layer_id, visible in self.layer_visible.items() if visible]
        dirty_flags = {
            "force": bool(force),
            "changed": bool(changed) if changed is not None else None,
            "globe_dirty": bool(getattr(self, "globe_dirty", False)),
            "overlay_dirty": bool(getattr(self, "overlay_dirty", False)),
            "hydrology_dirty": bool(getattr(self, "hydrology_dirty", False)),
            "boundary_dirty": bool(getattr(self, "boundary_dirty", False)),
            "boundary_hover_dirty": bool(getattr(self, "boundary_hover_dirty", False)),
        }
        return {
            "schema": "rrkal_displaytools.layer_render_plan_runtime_snapshot.v1",
            "source": "HybridRenderController.layer_render_plan_runtime_snapshot",
            "frame_index": int(getattr(self, "frame_index", 0)),
            "status": "snapshot_only",
            "runtime_optimization_applied": False,
            "optimization_target": "precompute_layer_state_then_single_render_pass",
            "visible_layers": visible_layers,
            "visible_layer_count": len(visible_layers),
            "selected_layer_semantic_target": getattr(self, "selected_layer_semantic_target", None),
            "dirty_flags": dirty_flags,
            "defer_vector_overlays": defer_vector_overlays,
            "batch_targets": [
                {"id": "globe_material", "source": "TaichiGlobe.render", "dirty_flag": "globe_dirty"},
                {"id": "hydrology_polylines", "source": "lake_overlay_rgba/river_overlay_rgba", "dirty_flag": "hydrology_dirty"},
                {"id": "boundary_and_maritime_lines", "source": "boundary_layer_rgba/boundary_overlay_rgba", "dirty_flag": "boundary_dirty"},
                {"id": "traffic_points", "source": "overlay_rgba/aircraft_overlay_rgba", "dirty_flag": "overlay_dirty"},
                {"id": "research_pins", "source": "pin_overlay_rgba", "dirty_flag": "overlay_dirty"},
                {"id": "vehicle_icons", "source": "vehicle_icon_overlay_rgba", "dirty_flag": "overlay_dirty"},
            ],
            "compose_order": ["globe_rgba", *[str(step.get("id")) for step in self.layer_render_plan_composition_steps()]],
            "composition_step_count": len(self.layer_render_plan_composition_steps()),
            "composition_helper": "HybridRenderController.apply_layer_render_plan_composition",
            "single_pass_target": "future_unified_taichi_render_plan",
            "current_path": "centralized_plan_helper_with_existing_overlay_composition",
        }

    def layer_render_plan_composition_steps(self) -> list[dict[str, object]]:
        steps: list[dict[str, object]] = [
            {"id": "lakes", "kind": "runtime_blend", "layer_id": "lakes", "overlay_attr": "lake_overlay_rgba"},
            {"id": "rivers", "kind": "runtime_blend", "layer_id": "rivers", "overlay_attr": "river_overlay_rgba"},
        ]
        if self.boundary_layer_rgba:
            for layer_id in ("borders", "territorial_sea", "eez", "high_seas"):
                if self.boundary_layer_rgba.get(layer_id) is not None:
                    steps.append({"id": layer_id, "kind": "runtime_blend", "layer_id": layer_id, "overlay_source": "boundary_layer_rgba"})
        else:
            steps.append(
                {
                    "id": "boundary_aggregate",
                    "kind": "alpha_blend",
                    "overlay_attr": "boundary_overlay_rgba",
                    "blend_mode": self.boundary_aggregate_blend_mode(),
                }
            )
        steps.extend(
            [
                {"id": "ais_overlay", "kind": "alpha_compose", "overlay_attr": "overlay_rgba"},
                {"id": "aircraft", "kind": "runtime_overlay", "layer_id": "aircraft", "overlay_attr": "aircraft_overlay_rgba"},
                {"id": "vehicle_icons", "kind": "runtime_overlay", "layer_id": "vehicle_icons", "overlay_attr": "vehicle_icon_overlay_rgba"},
                {"id": "pins", "kind": "runtime_overlay", "layer_id": "pins", "overlay_attr": "pin_overlay_rgba"},
                {"id": "style_profile_postprocess", "kind": "style_profile_postprocess"},
            ]
        )
        return steps

    def layer_render_plan_step_overlay(self, step: dict[str, object]) -> object:
        layer_id = str(step.get("layer_id") or step.get("id") or "")
        if step.get("overlay_source") == "boundary_layer_rgba":
            return self.boundary_layer_rgba.get(layer_id)
        if step.get("overlay_attr"):
            return getattr(self, str(step.get("overlay_attr")), None)
        return None

    def layer_render_plan_step_visible(self, step: dict[str, object]) -> bool:
        layer_key = str(step.get("layer_id") or step.get("id") or "")
        if layer_key in self.layer_visible:
            return bool(self.layer_visible.get(layer_key, False))
        return True

    def layer_render_plan_overlay_is_transparent(self, overlay: object) -> bool:
        if not isinstance(overlay, np.ndarray):
            return False
        if overlay.ndim < 3 or overlay.shape[-1] < 4:
            return False
        return not bool(np.any(overlay[..., 3]))

    def layer_render_plan_compose_queue(
        self,
        composition_steps: list[dict[str, object]],
    ) -> dict[str, object]:
        queue: list[dict[str, object]] = []
        skipped_steps: list[dict[str, object]] = []
        for index, step in enumerate(composition_steps):
            if not isinstance(step, dict):
                skipped_steps.append({"source_order": index, "id": "unknown_step", "reason": "malformed_step"})
                continue
            step_id = str(step.get("id") or step.get("layer_id") or f"step_{index}")
            kind = str(step.get("kind") or "")
            if kind == "style_profile_postprocess":
                queued = dict(step)
                queued["source_order"] = index
                queued["queue_order"] = len(queue)
                queued["compose_queue_reason"] = "postprocess_required"
                queue.append(queued)
                continue
            if not self.layer_render_plan_step_visible(step):
                skipped_steps.append({"source_order": index, "id": step_id, "kind": kind, "reason": "hidden_layer"})
                continue
            overlay = self.layer_render_plan_step_overlay(step)
            if overlay is None:
                skipped_steps.append({"source_order": index, "id": step_id, "kind": kind, "reason": "missing_overlay"})
                continue
            if self.layer_render_plan_overlay_is_transparent(overlay):
                skipped_steps.append({"source_order": index, "id": step_id, "kind": kind, "reason": "transparent_overlay"})
                continue
            queued = dict(step)
            queued["source_order"] = index
            queued["queue_order"] = len(queue)
            queued["compose_queue_reason"] = "executable_overlay"
            queue.append(queued)
        compose_runs_packet = self.layer_render_plan_compose_runs(queue)
        compose_run_parity_contract = self.layer_render_plan_compose_run_parity_contract(
            compose_runs_packet.get("runs", [])
            if isinstance(compose_runs_packet.get("runs"), list)
            else []
        )
        return {
            "schema": "rrkal_displaytools.layer_render_plan_compose_queue.v1",
            "source": "HybridRenderController.layer_render_plan_compose_queue",
            "status": "runtime_optimized",
            "optimization_applied": True,
            "optimization": "skip_hidden_missing_or_transparent_overlays_before_composition",
            "input_step_count": len(composition_steps),
            "executable_step_count": len(queue),
            "skipped_step_count": len(skipped_steps),
            "queue": queue,
            "skipped_steps": skipped_steps,
            "compose_runs_schema": "rrkal_displaytools.layer_render_plan_compose_runs.v1",
            "compose_runs": compose_runs_packet.get("runs", []),
            "compose_run_count": compose_runs_packet.get("run_count", 0),
            "compose_merge_candidate_run_count": compose_runs_packet.get("merge_candidate_run_count", 0),
            "compose_run_parity_contract_schema": "rrkal_displaytools.layer_render_plan_compose_run_parity_contract.v1",
            "compose_run_parity_contract": compose_run_parity_contract,
            "next_optimization_target": "collapse executable queue into fewer overlay composition passes",
        }

    def layer_render_plan_compose_runs(
        self,
        compose_queue: list[dict[str, object]],
    ) -> dict[str, object]:
        runs: list[dict[str, object]] = []
        current_run: dict[str, object] | None = None
        for step in compose_queue:
            if not isinstance(step, dict):
                continue
            kind = str(step.get("kind") or "unknown")
            step_id = str(step.get("id") or step.get("layer_id") or "unknown_step")
            queue_order = int(step.get("queue_order", len(runs)))
            if kind == "style_profile_postprocess":
                run_kind = "postprocess"
                merge_safe = False
                merge_reason = "full_frame_style_profile_boundary"
            elif kind == "alpha_compose":
                run_kind = "alpha_compose_overlays"
                merge_safe = True
                merge_reason = "adjacent_alpha_compose_overlays_can_be_collapsed_after_visual_parity_check"
            elif kind == "alpha_blend":
                run_kind = "alpha_blend_overlay"
                merge_safe = False
                merge_reason = "blend_mode_specific_overlay_boundary"
            elif kind in {"runtime_blend", "runtime_overlay"}:
                run_kind = "runtime_layer_overlay"
                merge_safe = False
                merge_reason = "preserve_per_layer_visibility_opacity_blend_semantics"
            else:
                run_kind = "unknown_overlay"
                merge_safe = False
                merge_reason = "unknown_runtime_semantics"
            can_extend = (
                current_run is not None
                and current_run.get("run_kind") == run_kind
                and current_run.get("merge_safe") is True
                and merge_safe
            )
            if not can_extend:
                current_run = {
                    "id": f"compose_run_{len(runs)}",
                    "run_kind": run_kind,
                    "merge_safe": merge_safe,
                    "merge_reason": merge_reason,
                    "start_queue_order": queue_order,
                    "end_queue_order": queue_order,
                    "step_ids": [],
                    "step_count": 0,
                    "current_runtime_path": "sequential_compose_queue_execution",
                    "next_runtime_path": "merged_overlay_pass" if merge_safe else "preserve_ordered_step_execution",
                }
                runs.append(current_run)
            current_run["end_queue_order"] = queue_order
            step_ids = current_run.get("step_ids")
            if isinstance(step_ids, list):
                step_ids.append(step_id)
            current_run["step_count"] = int(current_run.get("step_count", 0)) + 1
        return {
            "schema": "rrkal_displaytools.layer_render_plan_compose_runs.v1",
            "source": "HybridRenderController.layer_render_plan_compose_runs",
            "status": "ready",
            "run_count": len(runs),
            "merge_candidate_run_count": sum(1 for run in runs if run.get("merge_safe") is True),
            "runs": runs,
            "next_optimization_target": "merge safe adjacent alpha_compose overlays after visual parity smoke is available",
        }

    def layer_render_plan_compose_run_parity_contract(
        self,
        compose_runs: list[dict[str, object]],
    ) -> dict[str, object]:
        merge_candidates = [
            run
            for run in compose_runs
            if isinstance(run, dict) and run.get("merge_safe") is True
        ]
        return {
            "schema": "rrkal_displaytools.layer_render_plan_compose_run_parity_contract.v1",
            "source": "HybridRenderController.layer_render_plan_compose_run_parity_contract",
            "status": "required_before_runtime_merge" if merge_candidates else "no_merge_candidates",
            "runtime_merge_enabled": False,
            "merge_candidate_run_count": len(merge_candidates),
            "candidate_run_ids": [str(run.get("id")) for run in merge_candidates],
            "compare_method": "sequential_compose_queue_vs_merged_candidate_rgba_diff",
            "required_artifacts": [
                "baseline_sequential_frame_rgba",
                "merged_candidate_frame_rgba",
                "max_abs_diff",
                "changed_pixel_count",
                "renderer_output_metadata",
            ],
            "tolerance": {
                "max_abs_diff": 0,
                "changed_pixel_count": 0,
            },
            "gate": "block_compose_run_merge_until_visual_parity_passes",
            "parity_smoke_schema": "rrkal_displaytools.render_compose_parity_smoke.v1",
            "parity_smoke_script": "scripts\\render_compose_parity_smoke.ps1",
            "parity_smoke_manifest": "state/render_compose_parity_smoke_manifest.json",
            "parity_smoke_default_mode": "contract_only_until_artifacts_then_rgba_diff",
            "parity_smoke_precommit_command": "powershell -NoProfile -ExecutionPolicy Bypass -File scripts\\render_compose_parity_smoke.ps1 -ContractOnly",
            "parity_smoke_validates": ["png_dimensions_match", "max_abs_diff", "changed_pixel_count"],
            "parity_smoke_pass_fields": ["passed", "max_abs_diff", "changed_pixel_count", "diff_status"],
            "recommended_command": "powershell -NoProfile -ExecutionPolicy Bypass -File scripts\\render_compose_parity_smoke.ps1",
            "next_runtime_step": "add an opt-in merged alpha compose path and compare it against the sequential compose queue before enabling it by default",
        }

    def apply_layer_render_plan_composition(self, steps: list[dict[str, object]] | None = None) -> np.ndarray:
        frame = self.globe_rgba
        plan_steps = steps if isinstance(steps, list) else self.layer_render_plan_composition_steps()
        step_timing_ms: dict[str, float] = {}
        for step in plan_steps:
            if not isinstance(step, dict):
                continue
            step_started_at = time.perf_counter()
            kind = str(step.get("kind"))
            layer_id = str(step.get("layer_id") or step.get("id") or "")
            overlay = self.layer_render_plan_step_overlay(step)
            if kind == "runtime_blend" and overlay is not None:
                frame = self.compose_runtime_blend(frame, layer_id, overlay)
            elif kind == "alpha_blend" and overlay is not None:
                frame = alpha_blend_compose(frame, overlay, str(step.get("blend_mode") or "Normal"))
            elif kind == "alpha_compose" and overlay is not None:
                frame = alpha_compose(frame, overlay)
            elif kind == "runtime_overlay" and overlay is not None:
                frame = self.compose_runtime_overlay(frame, layer_id, overlay)
            elif kind == "style_profile_postprocess":
                frame = apply_style_profile(frame, getattr(self.args, "style_profile", "scientific"))
            phase_id = "postprocess" if kind == "style_profile_postprocess" else "compose_overlays"
            step_timing_ms[phase_id] = step_timing_ms.get(phase_id, 0.0) + (
                time.perf_counter() - step_started_at
            ) * 1000.0
        self.layer_render_step_timing_ms = {
            phase_id: round(elapsed_ms, 3)
            for phase_id, elapsed_ms in step_timing_ms.items()
        }
        return frame

    def merge_alpha_compose_overlay_run(self, overlays: list[np.ndarray]) -> np.ndarray | None:
        valid_overlays = [overlay for overlay in overlays if isinstance(overlay, np.ndarray)]
        if not valid_overlays:
            return None
        merged = np.zeros_like(valid_overlays[0], dtype=np.uint8)
        for overlay in valid_overlays:
            if overlay.shape != merged.shape:
                raise ValueError(f"Overlay shape {overlay.shape} does not match merged overlay {merged.shape}")
            bottom_alpha = merged[..., 3:4].astype(np.float32) / 255.0
            top_alpha = overlay[..., 3:4].astype(np.float32) / 255.0
            out_alpha = top_alpha + bottom_alpha * (1.0 - top_alpha)
            bottom_premul = merged[..., :3].astype(np.float32) / 255.0 * bottom_alpha
            top_premul = overlay[..., :3].astype(np.float32) / 255.0 * top_alpha
            out_premul = top_premul + bottom_premul * (1.0 - top_alpha)
            out_rgb = np.zeros_like(out_premul)
            np.divide(out_premul, out_alpha, out=out_rgb, where=out_alpha > 0.0)
            merged[..., :3] = np.clip(out_rgb * 255.0, 0.0, 255.0).astype(np.uint8)
            merged[..., 3] = np.clip(out_alpha[..., 0] * 255.0, 0.0, 255.0).astype(np.uint8)
        return merged

    def apply_layer_render_plan_merged_candidate_composition(
        self,
        steps: list[dict[str, object]] | None = None,
    ) -> tuple[np.ndarray, dict[str, object]]:
        frame = self.globe_rgba
        plan_steps = steps if isinstance(steps, list) else self.layer_render_plan_composition_steps()
        candidate_runs: list[dict[str, object]] = []
        index = 0
        while index < len(plan_steps):
            step = plan_steps[index]
            if not isinstance(step, dict):
                index += 1
                continue
            kind = str(step.get("kind"))
            layer_id = str(step.get("layer_id") or step.get("id") or "")
            overlay = self.layer_render_plan_step_overlay(step)
            if kind == "alpha_compose" and overlay is not None:
                run_steps = [step]
                overlays = [overlay]
                next_index = index + 1
                while next_index < len(plan_steps):
                    next_step = plan_steps[next_index]
                    if not isinstance(next_step, dict) or str(next_step.get("kind")) != "alpha_compose":
                        break
                    next_overlay = self.layer_render_plan_step_overlay(next_step)
                    if next_overlay is None:
                        break
                    run_steps.append(next_step)
                    overlays.append(next_overlay)
                    next_index += 1
                merged_overlay = self.merge_alpha_compose_overlay_run(overlays)
                if merged_overlay is not None:
                    frame = alpha_compose(frame, merged_overlay)
                candidate_runs.append(
                    {
                        "kind": "alpha_compose_overlays",
                        "start_queue_order": step.get("queue_order", index),
                        "end_queue_order": run_steps[-1].get("queue_order", next_index - 1),
                        "step_count": len(run_steps),
                        "step_ids": [
                            str(run_step.get("id") or run_step.get("layer_id") or "unknown_step")
                            for run_step in run_steps
                        ],
                        "merged": len(run_steps) > 1,
                        "candidate_path": "merged_overlay_then_alpha_compose",
                    }
                )
                index = next_index
                continue
            if kind == "runtime_blend" and overlay is not None:
                frame = self.compose_runtime_blend(frame, layer_id, overlay)
            elif kind == "alpha_blend" and overlay is not None:
                frame = alpha_blend_compose(frame, overlay, str(step.get("blend_mode") or "Normal"))
            elif kind == "runtime_overlay" and overlay is not None:
                frame = self.compose_runtime_overlay(frame, layer_id, overlay)
            elif kind == "style_profile_postprocess":
                frame = apply_style_profile(frame, getattr(self.args, "style_profile", "scientific"))
            index += 1
        packet = {
            "schema": "rrkal_displaytools.compose_run_parity_candidate.v1",
            "source": "HybridRenderController.apply_layer_render_plan_merged_candidate_composition",
            "status": "candidate_frame_generated",
            "runtime_merge_enabled": False,
            "candidate_run_count": len(candidate_runs),
            "merged_candidate_run_count": sum(1 for run in candidate_runs if run.get("merged") is True),
            "candidate_runs": candidate_runs,
            "boundary": "Candidate frame is opt-in parity evidence only; runtime compose merging remains disabled.",
        }
        return frame, packet

    def write_compose_parity_artifacts(self) -> None:
        artifact_dir_value = getattr(self.args, "compose_parity_artifact_dir", None)
        if not artifact_dir_value:
            return
        artifact_dir = Path(artifact_dir_value)
        baseline_path = artifact_dir / "baseline_sequential_frame_rgba.png"
        candidate_path = artifact_dir / "merged_candidate_frame_rgba.png"
        metadata_path = artifact_dir / "renderer_output_metadata.json"
        compose_queue = []
        if isinstance(getattr(self, "compiled_layer_render_plan", None), dict):
            plan_queue = self.compiled_layer_render_plan.get("compose_queue")
            if isinstance(plan_queue, list):
                compose_queue = plan_queue
        try:
            from PIL import Image

            artifact_dir.mkdir(parents=True, exist_ok=True)
            candidate_frame, candidate_packet = self.apply_layer_render_plan_merged_candidate_composition(compose_queue)
            Image.fromarray(self.frame_rgba, mode="RGBA").save(baseline_path)
            Image.fromarray(candidate_frame, mode="RGBA").save(candidate_path)
            metadata = {
                "schema": "rrkal_displaytools.compose_run_parity_artifacts.v1",
                "created_at_utc": datetime.datetime.now(datetime.timezone.utc).isoformat(),
                "status": "artifacts_written",
                "runtime_merge_enabled": False,
                "artifact_dir": str(artifact_dir),
                "baseline_artifact": str(baseline_path),
                "candidate_artifact": str(candidate_path),
                "metadata_artifact": str(metadata_path),
                "diff_command": "powershell -NoProfile -ExecutionPolicy Bypass -File scripts\\render_compose_parity_smoke.ps1",
                "compose_queue_count": len(compose_queue),
                "candidate": candidate_packet,
                "compiled_plan_schema": (
                    self.compiled_layer_render_plan.get("schema")
                    if isinstance(getattr(self, "compiled_layer_render_plan", None), dict)
                    else None
                ),
            }
            metadata_path.write_text(json.dumps(metadata, ensure_ascii=False, indent=2, default=str), encoding="utf-8")
            self.compose_parity_artifact_result = metadata
        except Exception as exc:
            self.compose_parity_artifact_result = {
                "schema": "rrkal_displaytools.compose_run_parity_artifacts.v1",
                "status": "write_failed",
                "error": str(exc),
                "artifact_dir": str(artifact_dir),
            }
            print(f"Unable to write compose parity artifacts: {exc}")

    def layer_render_plan_cache_key(
        self,
        runtime_snapshot: dict[str, object],
        composition_steps: list[dict[str, object]],
    ) -> str:
        visible_layers = runtime_snapshot.get("visible_layers") if isinstance(runtime_snapshot.get("visible_layers"), list) else []
        visible_layer_ids = [str(layer_id) for layer_id in visible_layers]
        payload = {
            "style_profile": getattr(self.args, "style_profile", "scientific"),
            "visible_layers": visible_layer_ids,
            "selected_layer_semantic_target": runtime_snapshot.get("selected_layer_semantic_target"),
            "dirty_flags": runtime_snapshot.get("dirty_flags"),
            "defer_vector_overlays": runtime_snapshot.get("defer_vector_overlays"),
            "composition_ids": [str(step.get("id")) for step in composition_steps],
            "boundary_layer_ids": sorted(str(layer_id) for layer_id in self.boundary_layer_rgba),
            "layer_opacity": {layer_id: self.layer_opacity_percent(layer_id) for layer_id in visible_layer_ids},
            "layer_blend": {layer_id: self.layer_blend_mode(layer_id) for layer_id in visible_layer_ids},
        }
        return json.dumps(payload, sort_keys=True, default=str)

    def layer_render_plan_cache_invalidation_reasons(
        self,
        runtime_snapshot: dict[str, object],
        cache_key: str,
    ) -> list[str]:
        reasons: list[str] = []
        dirty_flags = runtime_snapshot.get("dirty_flags") if isinstance(runtime_snapshot.get("dirty_flags"), dict) else {}
        for flag, value in dirty_flags.items():
            if value is True:
                reasons.append(f"dirty_flag:{flag}")
        cached_plan = getattr(self, "compiled_layer_render_plan", None)
        previous_key = getattr(self, "compiled_layer_render_plan_cache_key", None)
        if not isinstance(cached_plan, dict):
            reasons.append("no_previous_compiled_plan")
        elif previous_key != cache_key:
            reasons.append("cache_key_changed")
        if not reasons:
            reasons.append("cache_key_match")
        return reasons

    def layer_render_plan_cache_invalidation_scope(
        self,
        runtime_snapshot: dict[str, object],
        invalidation_reasons: list[str],
    ) -> list[dict[str, object]]:
        dirty_flags = runtime_snapshot.get("dirty_flags") if isinstance(runtime_snapshot.get("dirty_flags"), dict) else {}
        batch_targets = runtime_snapshot.get("batch_targets") if isinstance(runtime_snapshot.get("batch_targets"), list) else []
        scopes: list[dict[str, object]] = []
        for batch in batch_targets:
            if not isinstance(batch, dict):
                continue
            dirty_flag = str(batch.get("dirty_flag") or "")
            if dirty_flag and dirty_flags.get(dirty_flag) is True:
                scopes.append(
                    {
                        "scope": "batch",
                        "id": str(batch.get("id") or dirty_flag),
                        "dirty_flag": dirty_flag,
                        "source": batch.get("source"),
                    }
                )
        for global_flag in ("force", "changed"):
            if dirty_flags.get(global_flag) is True:
                scopes.append({"scope": "global", "id": global_flag, "dirty_flag": global_flag})
        if "cache_key_changed" in invalidation_reasons or "no_previous_compiled_plan" in invalidation_reasons:
            scopes.append({"scope": "plan", "id": "compiled_layer_render_plan", "dirty_flag": "cache_key"})
        if not scopes and "cache_key_match" in invalidation_reasons:
            scopes.append({"scope": "reuse", "id": "compiled_layer_render_plan", "dirty_flag": None})
        return scopes

    def layer_render_plan_batch_decisions(
        self,
        runtime_snapshot: dict[str, object],
        composition_steps: list[dict[str, object]],
        invalidation_scope: list[dict[str, object]],
    ) -> list[dict[str, object]]:
        dirty_flags = runtime_snapshot.get("dirty_flags") if isinstance(runtime_snapshot.get("dirty_flags"), dict) else {}
        batch_targets = runtime_snapshot.get("batch_targets") if isinstance(runtime_snapshot.get("batch_targets"), list) else []
        global_dirty = bool(dirty_flags.get("force") or dirty_flags.get("changed"))
        dirty_scope_ids = {
            str(scope.get("id"))
            for scope in invalidation_scope
            if isinstance(scope, dict) and scope.get("scope") in {"batch", "global", "plan"}
        }
        decisions: list[dict[str, object]] = []
        for batch in batch_targets:
            if not isinstance(batch, dict):
                continue
            batch_id = str(batch.get("id") or "")
            dirty_flag = str(batch.get("dirty_flag") or "")
            dirty = global_dirty or bool(dirty_flag and dirty_flags.get(dirty_flag)) or batch_id in dirty_scope_ids
            decisions.append(
                {
                    "scope": "batch",
                    "id": batch_id,
                    "dirty_flag": dirty_flag,
                    "source": batch.get("source"),
                    "decision": "rebuild_batch" if dirty else "reuse_batch",
                    "reason": f"dirty_flag:{dirty_flag}" if dirty and dirty_flag else ("global_dirty" if dirty else "cache_key_match"),
                }
            )

        layer_dirty_map = {
            "lakes": "hydrology_dirty",
            "rivers": "hydrology_dirty",
            "borders": "boundary_dirty",
            "territorial_sea": "boundary_dirty",
            "eez": "boundary_dirty",
            "high_seas": "boundary_dirty",
            "boundary_aggregate": "boundary_dirty",
            "ais_overlay": "overlay_dirty",
            "aircraft": "overlay_dirty",
            "vehicle_icons": "overlay_dirty",
            "pins": "overlay_dirty",
            "style_profile_postprocess": "globe_dirty",
        }
        for step in composition_steps:
            if not isinstance(step, dict):
                continue
            step_id = str(step.get("id") or step.get("layer_id") or "")
            dirty_flag = layer_dirty_map.get(step_id)
            dirty = global_dirty or bool(dirty_flag and dirty_flags.get(dirty_flag))
            kind = str(step.get("kind") or "")
            if kind == "style_profile_postprocess":
                decision = "postprocess_each_frame"
            else:
                decision = "compose_dirty_overlay" if dirty else "compose_cached_overlay"
            decisions.append(
                {
                    "scope": "layer",
                    "id": step_id,
                    "layer_id": step.get("layer_id"),
                    "kind": kind,
                    "dirty_flag": dirty_flag,
                    "decision": decision,
                    "reason": f"dirty_flag:{dirty_flag}" if dirty and dirty_flag else ("global_dirty" if dirty else "cache_key_match"),
                }
            )
        return decisions

    def layer_render_plan_apply_path(
        self,
        composition_steps: list[dict[str, object]],
        batch_decisions: list[dict[str, object]],
    ) -> list[dict[str, object]]:
        decisions_by_id = {
            str(decision.get("id")): decision
            for decision in batch_decisions
            if isinstance(decision, dict) and decision.get("scope") == "layer"
        }
        helper_by_kind = {
            "runtime_blend": "HybridRenderController.compose_runtime_blend",
            "alpha_blend": "alpha_blend_compose",
            "alpha_compose": "alpha_compose",
            "runtime_overlay": "HybridRenderController.compose_runtime_overlay",
            "style_profile_postprocess": "apply_style_profile",
        }
        path: list[dict[str, object]] = []
        for index, step in enumerate(composition_steps):
            if not isinstance(step, dict):
                continue
            step_id = str(step.get("id") or step.get("layer_id") or "")
            kind = str(step.get("kind") or "")
            decision = decisions_by_id.get(step_id, {})
            path.append(
                {
                    "order": index,
                    "id": step_id,
                    "layer_id": step.get("layer_id"),
                    "kind": kind,
                    "decision": decision.get("decision", "compose_cached_overlay"),
                    "apply_helper": helper_by_kind.get(kind, "unknown_apply_helper"),
                    "overlay_attr": step.get("overlay_attr"),
                    "overlay_source": step.get("overlay_source"),
                    "current_runtime_path": "HybridRenderController.apply_layer_render_plan_composition",
                    "single_pass_candidate": kind in {"runtime_blend", "alpha_blend", "alpha_compose", "runtime_overlay"},
                }
            )
        return path

    def layer_render_plan_execution_summary(
        self,
        apply_path: list[dict[str, object]],
        batch_decisions: list[dict[str, object]],
    ) -> dict[str, object]:
        helper_counts: dict[str, int] = {}
        decision_counts: dict[str, int] = {}
        single_pass_candidate_count = 0
        single_pass_blockers: list[str] = []
        for item in apply_path:
            if not isinstance(item, dict):
                continue
            helper = str(item.get("apply_helper") or "unknown_apply_helper")
            helper_counts[helper] = helper_counts.get(helper, 0) + 1
            decision = str(item.get("decision") or "unknown_decision")
            decision_counts[decision] = decision_counts.get(decision, 0) + 1
            if item.get("single_pass_candidate"):
                single_pass_candidate_count += 1
            else:
                single_pass_blockers.append(str(item.get("id") or "unknown_step"))
        batch_decision_counts: dict[str, int] = {}
        for item in batch_decisions:
            if not isinstance(item, dict):
                continue
            decision = str(item.get("decision") or "unknown_decision")
            batch_decision_counts[decision] = batch_decision_counts.get(decision, 0) + 1
        return {
            "schema": "rrkal_displaytools.layer_render_plan_execution_summary.v1",
            "source": "HybridRenderController.layer_render_plan_execution_summary",
            "current_execution_mode": "centralized_overlay_composition",
            "current_apply_helper": "HybridRenderController.apply_layer_render_plan_composition",
            "runtime_optimization_applied": False,
            "apply_path_count": len(apply_path),
            "batch_decision_count": len(batch_decisions),
            "single_pass_candidate_count": single_pass_candidate_count,
            "single_pass_blockers": single_pass_blockers,
            "helper_counts": helper_counts,
            "decision_counts": decision_counts,
            "batch_decision_counts": batch_decision_counts,
            "next_refactor_target": "replace per-step overlay helpers with a unified Taichi render/composite pass",
        }

    def layer_render_plan_execution_phases(
        self,
        apply_path: list[dict[str, object]],
        batch_decisions: list[dict[str, object]],
        execution_summary: dict[str, object],
    ) -> list[dict[str, object]]:
        def phase_decisions(items: list[dict[str, object]]) -> list[str]:
            values = sorted(
                {
                    str(item.get("decision") or "unknown_decision")
                    for item in items
                    if isinstance(item, dict)
                }
            )
            return values or ["none"]

        batch_items = [
            item
            for item in batch_decisions
            if isinstance(item, dict) and item.get("scope") == "batch"
        ]
        layer_items = [
            item
            for item in batch_decisions
            if isinstance(item, dict) and item.get("scope") == "layer"
        ]
        single_pass_items = [
            item
            for item in apply_path
            if isinstance(item, dict) and item.get("single_pass_candidate")
        ]
        blockers_value = execution_summary.get("single_pass_blockers")
        blockers = blockers_value if isinstance(blockers_value, list) else []
        postprocess_count = sum(
            1
            for item in apply_path
            if isinstance(item, dict) and item.get("kind") == "style_profile_postprocess"
        )
        return [
            {
                "id": "prepare_batches",
                "order": 0,
                "status": "planned_runtime_metadata",
                "item_count": len(batch_items),
                "decisions": phase_decisions(batch_items),
                "current_runtime_path": "precomputed_overlay_buffers",
                "future_single_pass_role": "prepare GPU-ready batch inputs",
            },
            {
                "id": "compose_overlays",
                "order": 1,
                "status": "current_runtime_path",
                "item_count": len(layer_items),
                "decisions": phase_decisions(layer_items),
                "current_runtime_path": "HybridRenderController.apply_layer_render_plan_composition",
                "future_single_pass_role": "replace per-layer overlay composition with one Taichi composite pass",
            },
            {
                "id": "postprocess",
                "order": 2,
                "status": "current_runtime_path",
                "item_count": postprocess_count,
                "decisions": ["postprocess_each_frame"],
                "current_runtime_path": "apply_style_profile",
                "future_single_pass_role": "remain final style pass unless folded into shader",
            },
            {
                "id": "future_single_pass_candidate",
                "order": 3,
                "status": "queued_after_module_decoupling",
                "item_count": len(single_pass_items),
                "decisions": ["single_pass_candidate"],
                "current_runtime_path": "metadata_only",
                "future_single_pass_role": "candidate steps for unified Taichi render/composite pass",
                "blockers": blockers,
            },
        ]

    def layer_render_plan_phase_timing_contract(
        self,
        execution_phases: list[dict[str, object]],
    ) -> dict[str, object]:
        phase_probe_points = []
        for phase in execution_phases:
            if not isinstance(phase, dict):
                continue
            phase_id = str(phase.get("id") or "unknown_phase")
            phase_probe_points.append(
                {
                    "phase_id": phase_id,
                    "order": phase.get("order"),
                    "probe_key": f"phase_ms.{phase_id}",
                    "recommended_start": f"{phase_id}.perf_counter_start",
                    "recommended_end": f"{phase_id}.perf_counter_end",
                    "metadata_field": f"phase_timing_ms.{phase_id}",
                }
            )
        return {
            "schema": "rrkal_displaytools.layer_render_plan_phase_timing_contract.v1",
            "source": "HybridRenderController.layer_render_plan_phase_timing_contract",
            "status": "probe_contract_ready",
            "runtime_measurements_available": False,
            "timing_unit": "milliseconds",
            "slow_frame_threshold_ms": 33.3,
            "phase_probe_count": len(phase_probe_points),
            "phase_probe_points": phase_probe_points,
            "summary_fields": ["total_ms", "phase_timing_ms", "slowest_phase_id", "frame_index"],
            "next_runtime_step": "wrap phase boundaries with perf_counter and write measured phase_timing_ms into renderer metadata",
        }

    def layer_render_plan_bottleneck_recommendation(
        self,
        phase_timing_runtime: dict[str, object],
    ) -> dict[str, object]:
        timing = phase_timing_runtime if isinstance(phase_timing_runtime, dict) else {}
        slowest_phase_id = str(timing.get("slowest_phase_id") or "unavailable")
        measured = bool(timing.get("runtime_measurements_available"))
        phase_plan = {
            "prepare_batches": {
                "recommended_next_action": "reuse_static_geometry_batches",
                "target_helper": "HybridRenderController.compile_layer_render_plan",
                "optimization_boundary": "cache renderer-ready hydrology, boundary, traffic and pin batches before composition",
            },
            "compose_overlays": {
                "recommended_next_action": "collapse_overlay_composition_passes",
                "target_helper": "HybridRenderController.apply_layer_render_plan_composition",
                "optimization_boundary": "replace per-layer alpha/runtime helper sequence with fewer unified composite passes",
            },
            "postprocess": {
                "recommended_next_action": "fold_or_defer_style_profile_postprocess",
                "target_helper": "apply_style_profile",
                "optimization_boundary": "avoid repeated full-frame tone/style work when style profile is unchanged",
            },
            "future_single_pass_candidate": {
                "recommended_next_action": "prototype_single_taichi_composite_pass",
                "target_helper": "HybridRenderController.apply_layer_render_plan_composition",
                "optimization_boundary": "consume compiled layer state in one Taichi render/composite path",
            },
        }
        selected = phase_plan.get(
            slowest_phase_id,
            {
                "recommended_next_action": "collect_more_runtime_phase_timing",
                "target_helper": "HybridRenderController.layer_render_plan_phase_timing_runtime_packet",
                "optimization_boundary": "wait for measured phase_timing_ms before changing render behavior",
            },
        )
        return {
            "schema": "rrkal_displaytools.layer_render_plan_bottleneck_recommendation.v1",
            "source": "HybridRenderController.layer_render_plan_bottleneck_recommendation",
            "status": "ready" if measured else "waiting_for_runtime_metadata",
            "basis_schema": timing.get("schema", "rrkal_displaytools.layer_render_plan_phase_timing_runtime.v1"),
            "slowest_phase_id": slowest_phase_id,
            "slowest_phase_ms": timing.get("slowest_phase_ms", 0.0),
            "total_ms": timing.get("total_ms", 0.0),
            "slow_frame": bool(timing.get("slow_frame", False)),
            "recommended_next_action": selected["recommended_next_action"],
            "target_helper": selected["target_helper"],
            "optimization_boundary": selected["optimization_boundary"],
            "runtime_optimization_applied": False,
            "next_commit_scope": "implement the recommended action only after smoke-gated phase timing confirms the bottleneck",
        }

    def layer_render_plan_phase_timing_runtime_packet(
        self,
        phase_timing_ms: dict[str, float],
        frame_index: int,
        total_ms: float,
    ) -> dict[str, object]:
        measured = {
            str(phase_id): round(float(elapsed_ms), 3)
            for phase_id, elapsed_ms in phase_timing_ms.items()
            if isinstance(phase_id, str)
        }
        slowest_phase_id = None
        slowest_phase_ms = 0.0
        if measured:
            slowest_phase_id = max(measured, key=lambda key: measured[key])
            slowest_phase_ms = measured.get(slowest_phase_id, 0.0)
        threshold_ms = 33.3
        packet = {
            "schema": "rrkal_displaytools.layer_render_plan_phase_timing_runtime.v1",
            "source": "HybridRenderController.layer_render_plan_phase_timing_runtime_packet",
            "status": "measured" if measured else "unavailable",
            "runtime_measurements_available": bool(measured),
            "timing_unit": "milliseconds",
            "total_ms": round(float(total_ms), 3),
            "phase_timing_ms": measured,
            "measured_phase_ids": list(measured.keys()),
            "slowest_phase_id": slowest_phase_id,
            "slowest_phase_ms": round(float(slowest_phase_ms), 3),
            "slow_frame": float(total_ms) > threshold_ms,
            "slow_frame_threshold_ms": threshold_ms,
            "frame_index": int(frame_index),
            "next_optimization_use": "identify whether prepare_batches, compose_overlays or postprocess dominates before replacing the render loop",
        }
        packet["bottleneck_recommendation_schema"] = "rrkal_displaytools.layer_render_plan_bottleneck_recommendation.v1"
        packet["bottleneck_recommendation"] = self.layer_render_plan_bottleneck_recommendation(packet)
        return packet

    def compile_layer_render_plan(
        self,
        changed: bool | None = None,
        force: bool = False,
        defer_vector_overlays: bool | None = None,
    ) -> dict[str, object]:
        composition_steps = self.layer_render_plan_composition_steps()
        runtime_snapshot = self.layer_render_plan_runtime_snapshot(
            changed=changed,
            force=force,
            defer_vector_overlays=defer_vector_overlays,
        )
        compose_queue_packet = self.layer_render_plan_compose_queue(composition_steps)
        cache_key = self.layer_render_plan_cache_key(runtime_snapshot, composition_steps)
        invalidation_reasons = self.layer_render_plan_cache_invalidation_reasons(runtime_snapshot, cache_key)
        invalidation_scope = self.layer_render_plan_cache_invalidation_scope(runtime_snapshot, invalidation_reasons)
        batch_decisions = self.layer_render_plan_batch_decisions(runtime_snapshot, composition_steps, invalidation_scope)
        apply_path = self.layer_render_plan_apply_path(composition_steps, batch_decisions)
        execution_summary = self.layer_render_plan_execution_summary(apply_path, batch_decisions)
        execution_phases = self.layer_render_plan_execution_phases(apply_path, batch_decisions, execution_summary)
        phase_timing_contract = self.layer_render_plan_phase_timing_contract(execution_phases)
        phase_timing_runtime = getattr(self, "layer_render_plan_phase_timing_runtime", {})
        phase_timing_runtime = phase_timing_runtime if isinstance(phase_timing_runtime, dict) else {}
        bottleneck_recommendation = phase_timing_runtime.get("bottleneck_recommendation") if isinstance(phase_timing_runtime.get("bottleneck_recommendation"), dict) else self.layer_render_plan_bottleneck_recommendation(phase_timing_runtime)
        cached_plan = getattr(self, "compiled_layer_render_plan", None)
        if isinstance(cached_plan, dict) and getattr(self, "compiled_layer_render_plan_cache_key", None) == cache_key:
            plan = dict(cached_plan)
            plan["cache_status"] = "reused"
            plan["cache_reuse_decision"] = "reused"
            plan["cache_invalidation_reasons"] = invalidation_reasons
            plan["cache_invalidation_scope"] = invalidation_scope
            plan["batch_decisions"] = batch_decisions
            plan["batch_decision_count"] = len(batch_decisions)
            plan["apply_path"] = apply_path
            plan["apply_path_count"] = len(apply_path)
            plan["execution_summary"] = execution_summary
            plan["execution_phases"] = execution_phases
            plan["execution_phases_schema"] = plan.get("execution_phases_schema", "rrkal_displaytools.layer_render_plan_execution_phases.v1")
            plan["execution_phase_count"] = len(execution_phases)
            plan["phase_timing_contract"] = phase_timing_contract
            plan["phase_timing_contract_schema"] = "rrkal_displaytools.layer_render_plan_phase_timing_contract.v1"
            plan["phase_timing_runtime"] = phase_timing_runtime
            plan["phase_timing_runtime_schema"] = "rrkal_displaytools.layer_render_plan_phase_timing_runtime.v1"
            plan["bottleneck_recommendation"] = bottleneck_recommendation
            plan["bottleneck_recommendation_schema"] = "rrkal_displaytools.layer_render_plan_bottleneck_recommendation.v1"
            plan["reuse_policy"] = "reuse_when_cache_key_matches_previous_compiled_plan"
            plan["reuse_boundary"] = plan.get("reuse_boundary", "valid_until_dirty_flags_or_camera_change")
            plan["frame_index"] = int(getattr(self, "frame_index", 0))
            plan["runtime_snapshot"] = runtime_snapshot
            plan["dirty_flags"] = runtime_snapshot.get("dirty_flags", {})
            plan["compose_queue"] = compose_queue_packet.get("queue", [])
            plan["compose_queue_schema"] = "rrkal_displaytools.layer_render_plan_compose_queue.v1"
            plan["compose_queue_packet"] = compose_queue_packet
            plan["compose_queue_count"] = compose_queue_packet.get("executable_step_count", 0)
            plan["compose_queue_skipped_count"] = compose_queue_packet.get("skipped_step_count", 0)
            plan["compose_runs"] = compose_queue_packet.get("compose_runs", [])
            plan["compose_runs_schema"] = "rrkal_displaytools.layer_render_plan_compose_runs.v1"
            plan["compose_run_count"] = compose_queue_packet.get("compose_run_count", 0)
            plan["compose_merge_candidate_run_count"] = compose_queue_packet.get("compose_merge_candidate_run_count", 0)
            plan["compose_run_parity_contract"] = compose_queue_packet.get("compose_run_parity_contract", {})
            plan["compose_run_parity_contract_schema"] = "rrkal_displaytools.layer_render_plan_compose_run_parity_contract.v1"
            return plan
        self.compiled_layer_render_plan_cache_key = cache_key
        return {
            "schema": "rrkal_displaytools.compiled_layer_render_plan.v1",
            "source": "HybridRenderController.compile_layer_render_plan",
            "status": "compiled_snapshot",
            "cache_status": "compiled",
            "cache_reuse_decision": "compiled",
            "cache_key": cache_key,
            "cache_invalidation_reasons": invalidation_reasons,
            "cache_invalidation_reason_schema": "rrkal_displaytools.layer_render_plan_cache_invalidation_reasons.v1",
            "cache_invalidation_scope": invalidation_scope,
            "cache_invalidation_scope_schema": "rrkal_displaytools.layer_render_plan_cache_invalidation_scope.v1",
            "batch_decisions": batch_decisions,
            "batch_decision_schema": "rrkal_displaytools.layer_render_plan_batch_decisions.v1",
            "batch_decision_count": len(batch_decisions),
            "apply_path": apply_path,
            "apply_path_schema": "rrkal_displaytools.layer_render_plan_apply_path.v1",
            "apply_path_count": len(apply_path),
            "execution_summary": execution_summary,
            "execution_summary_schema": "rrkal_displaytools.layer_render_plan_execution_summary.v1",
            "execution_phases": execution_phases,
            "execution_phases_schema": "rrkal_displaytools.layer_render_plan_execution_phases.v1",
            "execution_phase_count": len(execution_phases),
            "phase_timing_contract": phase_timing_contract,
            "phase_timing_contract_schema": "rrkal_displaytools.layer_render_plan_phase_timing_contract.v1",
            "phase_timing_runtime": phase_timing_runtime,
            "phase_timing_runtime_schema": "rrkal_displaytools.layer_render_plan_phase_timing_runtime.v1",
            "bottleneck_recommendation": bottleneck_recommendation,
            "bottleneck_recommendation_schema": "rrkal_displaytools.layer_render_plan_bottleneck_recommendation.v1",
            "reuse_policy": "reuse_when_cache_key_matches_previous_compiled_plan",
            "reuse_status_values": ["compiled", "reused"],
            "runtime_optimization_applied": False,
            "optimization_target": "precompute_layer_state_then_single_render_pass",
            "frame_index": int(getattr(self, "frame_index", 0)),
            "runtime_snapshot": runtime_snapshot,
            "dirty_flags": runtime_snapshot.get("dirty_flags", {}),
            "batch_targets": runtime_snapshot.get("batch_targets", []),
            "composition_steps": composition_steps,
            "composition_step_count": len(composition_steps),
            "compose_queue": compose_queue_packet.get("queue", []),
            "compose_queue_schema": "rrkal_displaytools.layer_render_plan_compose_queue.v1",
            "compose_queue_packet": compose_queue_packet,
            "compose_queue_count": compose_queue_packet.get("executable_step_count", 0),
            "compose_queue_skipped_count": compose_queue_packet.get("skipped_step_count", 0),
            "compose_runs": compose_queue_packet.get("compose_runs", []),
            "compose_runs_schema": "rrkal_displaytools.layer_render_plan_compose_runs.v1",
            "compose_run_count": compose_queue_packet.get("compose_run_count", 0),
            "compose_merge_candidate_run_count": compose_queue_packet.get("compose_merge_candidate_run_count", 0),
            "compose_run_parity_contract": compose_queue_packet.get("compose_run_parity_contract", {}),
            "compose_run_parity_contract_schema": "rrkal_displaytools.layer_render_plan_compose_run_parity_contract.v1",
            "compose_order": runtime_snapshot.get("compose_order", []),
            "apply_helper": "HybridRenderController.apply_layer_render_plan_composition",
            "single_pass_ready": False,
            "reuse_boundary": "valid_until_dirty_flags_or_camera_change",
        }

    def output_metadata_path(self) -> Path | None:
        if self.output_path is None:
            return None
        return self.output_path.with_suffix(self.output_path.suffix + ".metadata.json")

    def write_output_metadata(self) -> None:
        metadata_path = self.output_metadata_path()
        if metadata_path is None:
            return
        visible_layers = [layer_id for layer_id, visible in self.layer_visible.items() if visible]
        layer_opacity = {
            layer_id: opacity
            for layer_id in self.layer_visible
            for opacity in [self.layer_opacity_percent(layer_id)]
            if opacity is not None
        }
        layer_blend_mode = {
            layer_id: blend_mode
            for layer_id in self.layer_visible
            for blend_mode in [self.layer_blend_mode(layer_id)]
            if blend_mode is not None
        }
        payload = {
            "schema": "rrkal_displaytools.renderer_output_metadata.v1",
            "created_at_utc": datetime.datetime.now(datetime.timezone.utc).isoformat(),
            "output_file": str(self.output_path),
            "renderer": "taichi_global_bathymetry",
            "frame_index": self.frame_index,
            "width": self.width,
            "height": self.height,
            "style_profile": getattr(self.args, "style_profile", "scientific"),
            "topography_source": getattr(self.args, "topo_source", None),
            "data_mode": getattr(self.args, "data_mode", None),
            "ui_backend": getattr(self.args, "ui", None),
            "basemap_lod": self.basemap_lod,
            "render_ms": self.last_render_ms,
            "visible_layers": visible_layers,
            "layer_visible": {layer_id: bool(visible) for layer_id, visible in self.layer_visible.items()},
            "layer_opacity": layer_opacity,
            "layer_blend_mode": layer_blend_mode,
            "selected_layer_semantic_target": self.selected_layer_semantic_target,
            "last_layer_pick_result": self.last_layer_pick_result,
            "boundary_highlight": getattr(self, "boundary_highlight_state", {}),
            "layer_render_plan": getattr(self, "compiled_layer_render_plan", self.compile_layer_render_plan()),
            "closed_loop_status": renderer_closed_loop_status_packet(),
            "rrkal_data_manifest_ref": getattr(self.args, "rrkal_data_manifest_ref", ""),
            "rrkal_data_manifest_ref_boundary": "Reference-only; displaytools records the RRKAL manifest reference but does not discover, download, validate, import, or govern it.",
            "rrkal_boundary": {
                "displaytools_owns": ["renderer output artifact", "visual layer state", "render metadata sidecar"],
                "rrkal_owns": ["dataset discovery", "download/import/install registry", "manifest/cache governance"],
            },
        }
        try:
            metadata_path.parent.mkdir(parents=True, exist_ok=True)
            metadata_path.write_text(json.dumps(payload, ensure_ascii=False, indent=2, default=str), encoding="utf-8")
        except OSError as exc:
            print(f"Unable to write output metadata: {exc}")

    def export_timeline_animation_frames(self) -> dict[str, object]:
        export_dir_value = getattr(self.args, "timeline_export_dir", None)
        if not export_dir_value:
            return timeline_animation_export_packet(executed=False)
        export_dir = Path(export_dir_value)
        frame_count = max(1, int(getattr(self.args, "timeline_export_frames", 24)))
        fps = max(1.0, float(getattr(self.args, "timeline_export_fps", 24.0)))
        manifest_path_value = getattr(self.args, "timeline_export_manifest", None)
        manifest_path = Path(manifest_path_value) if manifest_path_value else export_dir / "timeline_animation_manifest.json"
        gif_path_value = getattr(self.args, "timeline_export_gif", None)
        gif_path = Path(gif_path_value) if gif_path_value else None
        mp4_path_value = getattr(self.args, "timeline_export_mp4", None)
        mp4_path = Path(mp4_path_value) if mp4_path_value else None
        export_dir.mkdir(parents=True, exist_ok=True)
        manifest_path.parent.mkdir(parents=True, exist_ok=True)
        if gif_path is not None:
            gif_path.parent.mkdir(parents=True, exist_ok=True)
        if mp4_path is not None:
            mp4_path.parent.mkdir(parents=True, exist_ok=True)
        state_payload = self.timeline_runtime_state if isinstance(self.timeline_runtime_state, dict) else {}
        runtime_keyframes = state_payload.get("timeline_keyframes")
        valid_keyframes = [keyframe for keyframe in runtime_keyframes if isinstance(keyframe, dict)] if isinstance(runtime_keyframes, list) else []
        timeline_state = state_payload.get("timeline_state")
        timeline_state = timeline_state if isinstance(timeline_state, dict) else {}
        playback = timeline_state.get("playback")
        playback = playback if isinstance(playback, dict) else {}
        playback["active"] = False
        playback["interval_ms"] = max(1, int(round(1000.0 / fps)))
        timeline_state["playback"] = playback
        state_payload["timeline_state"] = timeline_state
        self.timeline_runtime_state = state_payload
        previous_output_path = self.output_path
        self.output_path = None
        frames: list[dict[str, object]] = []
        gif_images = []
        mp4_images = []
        encoded_animation = False
        encoding_error = None
        encoded_video = False
        video_encoding_error = None
        try:
            from PIL import Image

            for frame_index in range(frame_count):
                position = 0.0
                if len(valid_keyframes) >= 2 and frame_count > 1:
                    position = frame_index * (len(valid_keyframes) - 1) / (frame_count - 1)
                active_index = int(math.floor(position)) if valid_keyframes else 0
                active_index = max(0, min(active_index, max(0, len(valid_keyframes) - 1)))
                fraction = max(0.0, min(1.0, position - active_index))
                playback["next_index"] = active_index
                timeline_state["playback"] = playback
                state_payload["timeline_state"] = timeline_state
                self.timeline_runtime_state = state_payload
                self.timeline_first_keyframe_apply_result = self.apply_timeline_first_keyframe_runtime_state()
                camera_packet = timeline_camera_keyframe_packet(timeline_state, valid_keyframes, instantiated=True)
                interpolation_state = dict(timeline_state)
                interpolation_playback = dict(playback)
                interpolation_playback["active"] = True
                interpolation_state["playback"] = interpolation_playback
                interval_s = max(0.05, float(playback["interval_ms"]) / 1000.0)
                export_last_step_at = time.time() - fraction * interval_s
                self.timeline_playback_last_step_at = export_last_step_at
                packet = timeline_ocean_material_interpolation_packet(
                    interpolation_state,
                    valid_keyframes,
                    instantiated=True,
                    last_step_at=export_last_step_at,
                )
                self.timeline_ocean_material_interpolation_result = packet
                camera_interpolation_packet = timeline_camera_interpolation_packet(
                    interpolation_state,
                    valid_keyframes,
                    instantiated=True,
                    last_step_at=export_last_step_at,
                )
                self.timeline_camera_interpolation_result = camera_interpolation_packet
                layer_opacity_packet = timeline_layer_opacity_interpolation_packet(
                    interpolation_state,
                    valid_keyframes,
                    instantiated=True,
                    last_step_at=export_last_step_at,
                )
                self.timeline_layer_opacity_interpolation_result = layer_opacity_packet
                layer_discrete_hold_packet = timeline_layer_discrete_hold_packet(
                    interpolation_state,
                    valid_keyframes,
                    instantiated=True,
                )
                self.timeline_layer_discrete_hold_result = layer_discrete_hold_packet
                interpolated = packet.get("interpolated")
                if isinstance(interpolated, dict):
                    for field, attr in {
                        "wave_strength": "ocean_wave_strength",
                        "roughness": "ocean_roughness",
                        "foam": "ocean_foam",
                    }.items():
                        if field in interpolated:
                            setattr(self.args, attr, max(0.0, min(1.0, float(interpolated[field]))))
                interpolated_camera = camera_interpolation_packet.get("interpolated")
                if isinstance(interpolated_camera, dict):
                    try:
                        self.yaw = float(interpolated_camera["yaw"])
                        self.pitch = float(interpolated_camera["pitch"])
                        self.zoom = max(0.08, min(float(interpolated_camera["zoom"]), 4.0))
                    except (KeyError, TypeError, ValueError):
                        pass
                interpolated_layer_opacity = layer_opacity_packet.get("interpolated_layer_opacity")
                if isinstance(interpolated_layer_opacity, dict):
                    for layer_key, opacity_percent in interpolated_layer_opacity.items():
                        layer_id = self.layer_runtime_id(str(layer_key)) if hasattr(self, "layer_runtime_id") else str(layer_key)
                        self.set_layer_opacity(layer_id, opacity_percent)
                frame = self.render_if_needed(force=True)
                if frame is None:
                    frame = self.frame_rgba
                frame_path = export_dir / f"timeline_frame_{frame_index:04d}.png"
                image = Image.fromarray(frame, mode="RGBA")
                image.save(frame_path)
                if gif_path is not None:
                    gif_images.append(image.copy())
                if mp4_path is not None:
                    mp4_images.append(image.convert("RGB").copy())
                frames.append(
                    {
                        "index": frame_index,
                        "file": str(frame_path),
                        "active_index": active_index,
                        "fraction": fraction,
                        "ocean_material": packet.get("interpolated", {}),
                        "camera": camera_interpolation_packet.get("interpolated") or camera_packet.get("camera"),
                        "layer_opacity": layer_opacity_packet.get("interpolated_layer_opacity", {}),
                        "layer_visible": layer_discrete_hold_packet.get("held_layer_visible", {}),
                        "layer_blend_mode": layer_discrete_hold_packet.get("held_layer_blend_mode", {}),
                    }
                )
            if gif_path is not None and gif_images:
                try:
                    duration_ms = max(1, int(round(1000.0 / fps)))
                    gif_images[0].save(
                        gif_path,
                        save_all=True,
                        append_images=gif_images[1:],
                        duration=duration_ms,
                        loop=0,
                        disposal=2,
                    )
                    encoded_animation = True
                except Exception as exc:
                    encoding_error = str(exc)
            if mp4_path is not None and mp4_images:
                try:
                    import imageio.v2 as imageio

                    with imageio.get_writer(str(mp4_path), fps=fps, codec="libx264", macro_block_size=1) as writer:
                        for image in mp4_images:
                            writer.append_data(np.asarray(image))
                    encoded_video = True
                except Exception as exc:
                    video_encoding_error = str(exc)
        finally:
            self.output_path = previous_output_path
        manifest = timeline_animation_export_packet(
            export_dir=export_dir,
            frame_count=frame_count,
            fps=fps,
            manifest_file=manifest_path,
            frames=frames,
            gif_file=gif_path,
            mp4_file=mp4_path,
            encoded_animation=encoded_animation,
            encoding_format="gif" if gif_path is not None else None,
            encoding_error=encoding_error,
            encoded_video=encoded_video,
            video_encoding_format="mp4" if mp4_path is not None else None,
            video_encoding_error=video_encoding_error,
            executed=True,
        )
        self.timeline_animation_export_result = manifest
        manifest_path.write_text(json.dumps(manifest, ensure_ascii=False, indent=2, default=str), encoding="utf-8")
        self.write_timeline_ack()
        return manifest

    def write_preview_frame_if_due(self, force: bool = False) -> None:
        if self.preview_frame_path is None:
            return
        now = time.time()
        if not force and now - self.preview_frame_last_write < self.preview_frame_interval:
            return
        try:
            from PIL import Image

            tmp_path = self.preview_frame_path.with_name(self.preview_frame_path.name + ".tmp.png")
            Image.fromarray(self.frame_rgba, mode="RGBA").save(tmp_path)
            tmp_path.replace(self.preview_frame_path)
            self.preview_frame_last_write = now
        except Exception as exc:
            print(f"Unable to write preview frame: {exc}")

    def write_pin_input_ack(self) -> None:
        if self.pin_input_ack_file is None:
            return
        pin_ids = [str(pin.get("id", "")) for pin in self.pin_records if isinstance(pin, dict)]
        selected_pin_exists = self.selected_pin_id in pin_ids if self.selected_pin_id is not None else False
        payload = {
            "schema": "rrkal_displaytools.renderer_pin_input_ack.v1",
            "updated_at_utc": datetime.datetime.now(datetime.timezone.utc).isoformat(),
            "pin_count": len(self.pin_records),
            "pin_ids_preview": pin_ids[:10],
            "selected_pin_id": self.selected_pin_id,
            "selected_pin_exists": selected_pin_exists,
            "pin_layer_enabled": bool(getattr(getattr(self, "args", None), "pin_layer", True)),
            "source": "taichi_global_bathymetry",
        }
        try:
            self.pin_input_ack_file.parent.mkdir(parents=True, exist_ok=True)
            self.pin_input_ack_file.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
        except OSError as exc:
            print(f"Unable to write pin input ack: {exc}")

