    def write_timeline_ack(self) -> None:
        if self.timeline_ack_file is None:
            return
        state_payload = self.timeline_runtime_state if isinstance(self.timeline_runtime_state, dict) else {}
        timeline_state = state_payload.get("timeline_state")
        timeline_state = timeline_state if isinstance(timeline_state, dict) else {}
        runtime_keyframes = state_payload.get("timeline_keyframes")
        runtime_keyframes = runtime_keyframes if isinstance(runtime_keyframes, list) else []
        keyframe_count = timeline_state.get("keyframe_count")
        if not isinstance(keyframe_count, int):
            keyframe_count = len(runtime_keyframes)
        active_step_state = timeline_active_step_state_packet(timeline_state, runtime_keyframes)
        step_playback = timeline_step_playback_packet(
            timeline_state,
            runtime_keyframes,
            instantiated=True,
            step_count=int(getattr(self, "timeline_playback_step_count", 0)),
            last_step_at_utc=getattr(self, "timeline_playback_last_step_utc", None),
        )
        ocean_material_interpolation = getattr(
            self,
            "timeline_ocean_material_interpolation_result",
            timeline_ocean_material_interpolation_packet(
                timeline_state,
                runtime_keyframes,
                instantiated=True,
                last_step_at=getattr(self, "timeline_playback_last_step_at", None),
            ),
        )
        camera_interpolation = getattr(
            self,
            "timeline_camera_interpolation_result",
            timeline_camera_interpolation_packet(
                timeline_state,
                runtime_keyframes,
                instantiated=True,
                last_step_at=getattr(self, "timeline_playback_last_step_at", None),
            ),
        )
        payload = {
            "schema": "rrkal_displaytools.renderer_timeline_ack.v1",
            "updated_at_utc": datetime.datetime.now(datetime.timezone.utc).isoformat(),
            "received": self.timeline_runtime_state is not None and self.timeline_runtime_state_error is None,
            "timeline_runtime_state_file": str(self.timeline_state_file) if self.timeline_state_file is not None else None,
            "timeline_runtime_state_schema": state_payload.get("schema"),
            "timeline_state_schema": timeline_state.get("schema"),
            "keyframe_count": keyframe_count,
            "playback_mode": timeline_state.get("playback", {}).get("mode")
            if isinstance(timeline_state.get("playback"), dict)
            else None,
            "playback_readiness": timeline_playback_readiness_packet(),
            "playback_plan": timeline_playback_plan_packet(runtime_keyframes),
            "segment_state": timeline_segment_state_packet(runtime_keyframes, active_step_state.get("active_index")),
            "active_step_state": active_step_state,
            "step_playback": step_playback,
            "ocean_material_interpolation": ocean_material_interpolation,
            "animation_export": getattr(self, "timeline_animation_export_result", timeline_animation_export_packet(executed=False)),
            "camera_keyframe": timeline_camera_keyframe_packet(timeline_state, runtime_keyframes, instantiated=True),
            "camera_interpolation": camera_interpolation,
            "layer_opacity_interpolation": getattr(
                self,
                "timeline_layer_opacity_interpolation_result",
                timeline_layer_opacity_interpolation_packet(
                    timeline_state,
                    runtime_keyframes,
                    instantiated=True,
                    last_step_at=getattr(self, "timeline_playback_last_step_at", None),
                ),
            ),
            "layer_discrete_hold": getattr(
                self,
                "timeline_layer_discrete_hold_result",
                timeline_layer_discrete_hold_packet(timeline_state, runtime_keyframes, instantiated=True),
            ),
            "first_keyframe_apply": getattr(
                self,
                "timeline_first_keyframe_apply_result",
                timeline_first_keyframe_apply_preview_packet(runtime_keyframes, active_step_state=active_step_state),
            ),
            "applies": ["input_acknowledgement"],
            "pending": [
                "blend_crossfade_interpolation",
                "visibility_fade_interpolation",
            ],
            "error": self.timeline_runtime_state_error,
            "source": "taichi_global_bathymetry",
        }
        try:
            self.timeline_ack_file.parent.mkdir(parents=True, exist_ok=True)
            self.timeline_ack_file.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
        except OSError as exc:
            print(f"Unable to write timeline ack: {exc}")

    def nearest_pin_hit(self, x: float, y: float, radius: float | None = None) -> dict[str, object] | None:
        if not self.layer_visible.get("pins", True):
            return None
        if not self.current_pin_projections:
            return None
        pick_radius = float(radius if radius is not None else getattr(self.args, "pin_pick_radius", 18.0))
        best: dict[str, object] | None = None
        best_dist2 = pick_radius * pick_radius
        for pin in self.current_pin_projections:
            if pin.get("visible") is not True:
                continue
            try:
                dx = float(pin["screen_x"]) - float(x)
                dy = float(pin["screen_y"]) - float(y)
            except (KeyError, TypeError, ValueError):
                continue
            dist2 = dx * dx + dy * dy
            if dist2 <= best_dist2:
                best_dist2 = dist2
                best = dict(pin)
                best["pick_distance_px"] = math.sqrt(dist2)
        return best

    def pick_pin(self, x: float, y: float) -> bool:
        hit = self.nearest_pin_hit(x, y)
        if hit is None:
            return False
        self.selected_pin_hit = hit
        self.selected_pin_id = str(hit.get("id", ""))
        self.selected_vehicle = None
        self.selected_boundary_hit = build_empty_boundary_hit()
        self.selected_hydrology_hit = {}
        self.overlay_dirty = True
        self.write_pin_pick_state("selected", hit)
        return True

    def set_pin_hover(self, x: float, y: float) -> None:
        self.hover_pin_hit = self.nearest_pin_hit(x, y, radius=float(getattr(self.args, "pin_pick_radius", 18.0)))
        hover_id = str(self.hover_pin_hit.get("id")) if self.hover_pin_hit is not None else None
        if hover_id != self._last_hover_pin_id:
            self._last_hover_pin_id = hover_id
            self.write_pin_pick_state("hover", self.hover_pin_hit)

    def pick_vehicle(self, x: float, y: float, source_filter: set[str] | None = None) -> None:
        had_pin_state = self.selected_pin_hit is not None or self.hover_pin_hit is not None or self.selected_pin_id is not None
        self.selected_pin_hit = None
        self.hover_pin_hit = None
        self.selected_pin_id = None
        self.selected_boundary_hit = build_empty_boundary_hit()
        self.selected_hydrology_hit = {}
        self.overlay_dirty = True
        if had_pin_state:
            self.write_pin_pick_state("cleared", None)
        radius = float(getattr(self.args, "icon_pick_radius", 14.0))
        best_row = None
        best_dist2 = radius * radius
        for source_name, frame in (("AIS", self.current_projected), ("ADS-B", self.current_aircraft_projected)):
            if source_filter is not None and source_name not in source_filter:
                continue
            if frame.empty:
                continue
            dx = frame["screen_x"].to_numpy(dtype=np.float32) - float(x)
            dy = frame["screen_y"].to_numpy(dtype=np.float32) - float(y)
            dist2 = dx * dx + dy * dy
            index = int(np.argmin(dist2))
            if float(dist2[index]) <= best_dist2:
                best_dist2 = float(dist2[index])
                row = frame.iloc[index].copy()
                row["source"] = source_name
                best_row = row
        self.selected_vehicle = best_row

    def nearest_boundary_hit(
        self,
        x: float,
        y: float,
        target_layers: set[str] | None = None,
        radius_px: float = 10.0,
    ) -> dict[str, object]:
        best = build_empty_boundary_hit()
        for layer_id, overlay in getattr(self, "boundary_overlays", {}).items():
            if target_layers is not None and layer_id not in target_layers:
                continue
            if not self.layer_visible.get(layer_id, True) or overlay is None:
                continue
            hit = overlay.hit_test(
                x,
                y,
                self.yaw,
                self.pitch,
                self.zoom,
                self.flip_longitude,
                self.flip_latitude,
                radius_px=radius_px,
            )
            if hit and hit["distance_px"] < best["distance_px"]:
                best = {
                    "layer_id": layer_id,
                    "name": self.layer_label(layer_id),
                    "line_index": hit.get("line_index"),
                    "distance_px": hit["distance_px"],
                }
                if isinstance(hit.get("feature"), dict):
                    best["feature"] = hit["feature"]
        if best.get("layer_id"):
            return best
        best_area = float("inf")
        for layer_id, overlay in getattr(self, "boundary_overlays", {}).items():
            if target_layers is not None and layer_id not in target_layers:
                continue
            if not self.layer_visible.get(layer_id, True) or overlay is None:
                continue
            hit = overlay.area_hit_test(
                x,
                y,
                self.yaw,
                self.pitch,
                self.zoom,
                self.flip_longitude,
                self.flip_latitude,
            )
            if hit and float(hit.get("area_px2", float("inf"))) < best_area:
                best_area = float(hit.get("area_px2", float("inf")))
                best = {
                    "layer_id": layer_id,
                    "line_index": hit["line_index"],
                    "distance_px": hit.get("distance_px", 0.0),
                    "screen_x": hit.get("screen_x", x),
                    "screen_y": hit.get("screen_y", y),
                    "area_px2": hit.get("area_px2"),
                    "hit_kind": hit.get("hit_kind", "closed_ring_area"),
                }
                if isinstance(hit.get("feature"), dict):
                    best["feature"] = hit["feature"]
        return best

    def nearest_hydrology_hit(self, x: float, y: float, layer_id: str, radius_px: float = 12.0) -> dict[str, object]:
        overlay = getattr(self, "hydrology_overlays", {}).get(layer_id)
        if overlay is None or not self.layer_visible.get(layer_id, True):
            return {}
        hit = overlay.hit_test(
            x,
            y,
            self.yaw,
            self.pitch,
            self.zoom,
            self.flip_longitude,
            self.flip_latitude,
            radius_px=radius_px,
        )
        if not hit:
            return {}
        out = {
            "layer_id": layer_id,
            "name": self.layer_label(layer_id),
            "line_index": hit.get("line_index"),
            "distance_px": hit.get("distance_px"),
            "screen_x": hit.get("screen_x"),
            "screen_y": hit.get("screen_y"),
        }
        if isinstance(hit.get("feature"), dict):
            out["feature"] = hit["feature"]
        return out

    def pick_hydrology_layer(self, layer_id: str, x: float, y: float) -> bool:
        hit = self.nearest_hydrology_hit(x, y, layer_id, radius_px=12.0)
        self.selected_hydrology_hit = hit
        picked = bool(hit.get("layer_id"))
        had_pin_state = self.selected_pin_hit is not None or self.hover_pin_hit is not None or self.selected_pin_id is not None
        self.selected_pin_hit = None
        self.hover_pin_hit = None
        self.selected_pin_id = None
        self.selected_vehicle = None
        self.selected_boundary_hit = build_empty_boundary_hit()
        self.last_layer_pick_result = {
            "schema": "rrkal_displaytools.renderer_layer_pick_result.v1",
            "event": "selected_layer_pick",
            "renderer_layer": layer_id,
            "picker": "hydrology_line",
            "hit": picked,
            "hit_detail": hit if picked else None,
            "frame_index": self.frame_index,
        }
        if picked:
            self.overlay_dirty = True
        if had_pin_state:
            self.write_pin_pick_state("cleared", None)
        self.write_layer_pick_state()
        return picked

    def pick_boundary_layer(self, layer_id: str, x: float, y: float) -> bool:
        hit = self.nearest_boundary_hit(x, y, {layer_id}, radius_px=12.0)
        self.selected_boundary_hit = hit
        self.selected_hydrology_hit = {}
        picked = bool(hit.get("layer_id"))
        had_pin_state = self.selected_pin_hit is not None or self.hover_pin_hit is not None or self.selected_pin_id is not None
        self.selected_pin_hit = None
        self.hover_pin_hit = None
        self.selected_pin_id = None
        self.selected_vehicle = None
        self.last_layer_pick_result = {
            "schema": "rrkal_displaytools.renderer_layer_pick_result.v1",
            "event": "selected_layer_pick",
            "renderer_layer": layer_id,
            "picker": "boundary_area" if hit.get("hit_kind") == "closed_ring_area" else "boundary_line",
            "hit": picked,
            "hit_detail": hit if picked else None,
            "frame_index": self.frame_index,
        }
        if picked:
            self.hover_boundary_hit = hit
            self.boundary_hover_dirty = True
            self.boundary_dirty = True
            self.overlay_dirty = True
        if had_pin_state:
            self.write_pin_pick_state("cleared", None)
        self.write_layer_pick_state()
        return picked

    def pick_selected_layer_target(self, x: float, y: float) -> bool:
        self.last_layer_pick_screen = {"screen_x": float(x), "screen_y": float(y)}
        layer_id = self.selected_renderer_layer_id
        if layer_id == "pins":
            had_pin_state = self.selected_pin_hit is not None or self.hover_pin_hit is not None or self.selected_pin_id is not None
            picked = self.pick_pin(x, y)
            if not picked:
                self.selected_pin_hit = None
                self.hover_pin_hit = None
                self.selected_pin_id = None
                self.selected_vehicle = None
                self.selected_boundary_hit = build_empty_boundary_hit()
                self.selected_hydrology_hit = {}
                if had_pin_state:
                    self.write_pin_pick_state("cleared", None)
            self.last_layer_pick_result = {
                "schema": "rrkal_displaytools.renderer_layer_pick_result.v1",
                "event": "selected_layer_pick",
                "renderer_layer": layer_id,
                "picker": "pin",
                "hit": picked,
                "frame_index": self.frame_index,
            }
            self.write_layer_pick_state()
            return picked
        if layer_id in {"aircraft", "vehicle_icons"}:
            source_filter = {"ADS-B"} if layer_id == "aircraft" else None
            self.pick_vehicle(x, y, source_filter=source_filter)
            picked = self.selected_vehicle is not None
            self.last_layer_pick_result = {
                "schema": "rrkal_displaytools.renderer_layer_pick_result.v1",
                "event": "selected_layer_pick",
                "renderer_layer": layer_id,
                "picker": "traffic_point",
                "hit": picked,
                "frame_index": self.frame_index,
            }
            self.write_layer_pick_state()
            return picked
        if layer_id in BOUNDARY_SPECS:
            return self.pick_boundary_layer(layer_id, x, y)
        if layer_id in HYDROLOGY_SPECS:
            return self.pick_hydrology_layer(layer_id, x, y)
        if layer_id:
            self.selected_hydrology_hit = {}
            self.selected_boundary_hit = build_empty_boundary_hit()
            had_pin_state = self.selected_pin_hit is not None or self.hover_pin_hit is not None or self.selected_pin_id is not None
            self.selected_pin_hit = None
            self.hover_pin_hit = None
            self.selected_pin_id = None
            self.selected_vehicle = None
            self.last_layer_pick_result = {
                "schema": "rrkal_displaytools.renderer_layer_pick_result.v1",
                "event": "selected_layer_pick",
                "renderer_layer": layer_id,
                "picker": "none",
                "hit": False,
                "frame_index": self.frame_index,
            }
            if had_pin_state:
                self.write_pin_pick_state("cleared", None)
            self.write_layer_pick_state()
            return False
        picked_pin = self.pick_pin(x, y)
        if picked_pin:
            self.last_layer_pick_result = {
                "schema": "rrkal_displaytools.renderer_layer_pick_result.v1",
                "event": "legacy_pick",
                "renderer_layer": "pins",
                "picker": "pin",
                "hit": True,
                "frame_index": self.frame_index,
            }
            self.write_layer_pick_state()
            return True
        self.pick_vehicle(x, y)
        picked_vehicle = self.selected_vehicle is not None
        self.last_layer_pick_result = {
            "schema": "rrkal_displaytools.renderer_layer_pick_result.v1",
            "event": "legacy_pick",
            "renderer_layer": "vehicle_icons",
            "picker": "traffic_point",
            "hit": picked_vehicle,
            "frame_index": self.frame_index,
        }
        self.write_layer_pick_state()
        return picked_vehicle

    def hit_test_scale_bar(self, x: float, y: float) -> bool:
        if not bool(getattr(self.args, "scale_bar", True)):
            return False
        bar_x = float(getattr(self.args, "scale_bar_x", 32.0))
        bar_y = float(getattr(self.args, "scale_bar_y", max(40.0, self.height - 54.0)))
        return bar_x - 10.0 <= float(x) <= bar_x + 250.0 and bar_y - 24.0 <= float(y) <= bar_y + 28.0

    def set_scale_bar_position(self, x: float, y: float) -> None:
        self.args.scale_bar_x = max(0.0, min(float(x), max(0.0, self.width - 240.0)))
        self.args.scale_bar_y = max(24.0, min(float(y), max(24.0, self.height - 24.0)))

    def set_scale_bar_opacity(self, value: float) -> None:
        self.args.scale_bar_opacity = max(0.0, min(float(value), 1.0))

    def set_boundary_hover(self, x: float, y: float) -> None:
        boundary_highlight = getattr(self, "boundary_highlight_state", {})
        highlight_enabled = bool(boundary_highlight.get("enabled", False)) if isinstance(boundary_highlight, dict) else False
        highlight_trigger = str(boundary_highlight.get("trigger", "hover")) if isinstance(boundary_highlight, dict) else "hover"
        if not highlight_enabled or highlight_trigger not in {"hover", "hover_or_selected"}:
            empty = build_empty_boundary_hit()
            if empty != self.hover_boundary_hit:
                self.hover_boundary_hit = empty
                self.boundary_hover_dirty = True
                self.boundary_dirty = True
            return
        target_layers = set(boundary_highlight.get("renderer_target_layers", [])) if isinstance(boundary_highlight, dict) else set()
        best = self.nearest_boundary_hit(x, y, target_layers, radius_px=10.0)
        if best != self.hover_boundary_hit:
            self.hover_boundary_hit = best
            self.boundary_hover_dirty = True
            self.boundary_dirty = True

    def boundary_layer_status_text(self, layer_id: str) -> str:
        overlay = getattr(self, "boundary_overlays", {}).get(layer_id)
        count = len(getattr(overlay, "lines", [])) if overlay else 0
        decision = self.boundary_lod_policy.decision(self.basemap_lod, layer_id)
        manifest = decision["manifest"]
        return (
            f"{layer_id}: {count:,} lines; provider={decision['provider_id']}; "
            f"source={manifest['source_url']}; input={decision['renderer_input']}; "
            f"decimate={decision['decimate']}; {decision['status']}"
        )

    def boundary_provider_decisions_text(self) -> str:
        lines = [f"Boundary provider decisions for LOD={self.basemap_lod}"]
        for layer_id in BOUNDARY_SPECS:
            decision = self.boundary_lod_policy.decision(self.basemap_lod, layer_id)
            manifest = decision["manifest"]
            lines.append(f"- {layer_id}: {decision['provider_id']}")
            lines.append(f"  source: {manifest['source_url']}")
            lines.append(f"  adapter target: {decision['target_adapter']}")
            lines.append(f"  renderer input: {decision['renderer_input']}")
            lines.append(f"  decimate: {decision['decimate']}")
            lines.append(f"  cache: {manifest['cache_path']}")
            lines.append(f"  status: {decision['status']}")
        return "\n".join(lines)

    def set_boundary_opacity(self, layer_id: str, value: float) -> None:
        attr = {
            "borders": "border_opacity",
            "territorial_sea": "territorial_sea_opacity",
            "eez": "eez_opacity",
            "high_seas": "high_seas_opacity",
        }.get(layer_id, f"{layer_id}_opacity")
        setattr(self.args, attr, max(0.0, min(float(value), 1.0)))
        self.boundary_dirty = True
        self.overlay_dirty = True

    def set_boundary_width(self, layer_id: str, value: int) -> None:
        attr = {
            "borders": "border_width",
            "territorial_sea": "territorial_sea_width",
            "eez": "eez_width",
            "high_seas": "high_seas_width",
        }.get(layer_id, f"{layer_id}_width")
        setattr(self.args, attr, max(1, int(value)))
        self.boundary_dirty = True
        self.overlay_dirty = True

    def reload_boundary_layer(self, layer_id: str, file_path: str | None = None, url: str | None = None) -> None:
        spec = BOUNDARY_SPECS.get(layer_id)
        if not spec:
            return
        prefix = spec.get("prefix", layer_id)
        setattr(self.args, f"{prefix}_file", (file_path or "").strip() or None)
        setattr(self.args, f"{prefix}_url", (url or "").strip() or None)
        self.boundary_overlays[layer_id] = self._load_single_boundary_overlay(layer_id)
        self.boundary_dirty = True
        self.overlay_dirty = True

    def reload_topography_step(self, step: int) -> None:
        self.args.topo_step = max(1, int(step))
        self.globe_dirty = True
        self.overlay_dirty = True

    def reload_ice_source(self, source: str) -> None:
        self.args.ice_source = str(source or "auto")
        self.globe_dirty = True

